use super::CoreSymbol;

pub fn core_symbols() -> Vec<CoreSymbol> {
    vec![
        CoreSymbol { name: "*".to_string(), params: "([] [x] [x y] [x y & more])".to_string(), doc: "Returns the product of nums. (*) returns 1. Does not auto-promote\n  longs, will throw on overflow. See also: *'".to_string() },
        CoreSymbol { name: "*'".to_string(), params: "([] [x] [x y] [x y & more])".to_string(), doc: "Returns the product of nums. (*') returns 1. Supports arbitrary precision.\n  See also: *".to_string() },
        CoreSymbol { name: "*1".to_string(), params: "".to_string(), doc: "bound in a repl thread to the most recent value printed".to_string() },
        CoreSymbol { name: "*2".to_string(), params: "".to_string(), doc: "bound in a repl thread to the second most recent value printed".to_string() },
        CoreSymbol { name: "*3".to_string(), params: "".to_string(), doc: "bound in a repl thread to the third most recent value printed".to_string() },
        CoreSymbol { name: "*assert*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*clojure-version*".to_string(), params: "".to_string(), doc: "The version info for Clojure core, as a map containing :major :minor \n  :incremental and :qualifier keys. Feature releases may increment \n  :minor and/or :major, bugfix releases will increment :incremental. \n  Possible values of :qualifier include \"GA\", \"SNAPSHOT\", \"RC-x\" \"BETA-x\"".to_string() },
        CoreSymbol { name: "*command-line-args*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*compile-files*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*compile-path*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*compiler-options*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*data-readers*".to_string(), params: "".to_string(), doc: "Map from reader tag symbols to data reader Vars.\n\n  When Clojure starts, it searches for files named 'data_readers.clj'\n  and 'data_readers.cljc' at the root of the classpath. Each such file\n  must contain a literal map of symbols, like this:\n\n      {foo/bar my.project.foo/bar\n       foo/baz my.project/baz}\n\n  The first symbol in each pair is a tag that will be recognized by\n  the Clojure reader. The second symbol in the pair is the\n  fully-qualified name of a Var which will be invoked by the reader to\n  parse the form following the tag. For example, given the\n  data_readers.clj file above, the Clojure reader would parse this\n  form:\n\n      #foo/bar [1 2 3]\n\n  by invoking the Var #'my.project.foo/bar on the vector [1 2 3]. The\n  data reader function is invoked on the form AFTER it has been read\n  as a normal Clojure data structure by the reader.\n\n  Reader tags without namespace qualifiers are reserved for\n  Clojure. Default reader tags are defined in\n  clojure.core/default-data-readers but may be overridden in\n  data_readers.clj, data_readers.cljc, or by rebinding this Var.".to_string() },
        CoreSymbol { name: "*default-data-reader-fn*".to_string(), params: "".to_string(), doc: "When no data reader is found for a tag and *default-data-reader-fn*\n  is non-nil, it will be called with two arguments,\n  the tag and the value.  If *default-data-reader-fn* is nil (the\n  default), an exception will be thrown for the unknown tag.".to_string() },
        CoreSymbol { name: "*e".to_string(), params: "".to_string(), doc: "bound in a repl thread to the most recent exception caught by the repl".to_string() },
        CoreSymbol { name: "*err*".to_string(), params: "".to_string(), doc: " A java.io.Writer object representing standard error for print operations.".to_string() },
        CoreSymbol { name: "*file*".to_string(), params: "".to_string(), doc: "The path of the file being evaluated, as a String.\n\n  When there is no file, e.g. in the REPL, the value is not defined.".to_string() },
        CoreSymbol { name: "*flush-on-newline*".to_string(), params: "".to_string(), doc: "When set to true, output will be flushed whenever a newline is printed.\n\n  Defaults to true.".to_string() },
        CoreSymbol { name: "*in*".to_string(), params: "".to_string(), doc: "A java.io.Reader object representing standard input for read operations.".to_string() },
        CoreSymbol { name: "*math-context*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*ns*".to_string(), params: "".to_string(), doc: "A sci.lang.Namespace object representing the current namespace.".to_string() },
        CoreSymbol { name: "*out*".to_string(), params: "".to_string(), doc: "A java.io.Writer object representing standard output for print operations.".to_string() },
        CoreSymbol { name: "*print-dup*".to_string(), params: "".to_string(), doc: "When set to logical true, objects will be printed in a way that preserves\n  their type when read in later.\n\n  Defaults to false.".to_string() },
        CoreSymbol { name: "*print-length*".to_string(), params: "".to_string(), doc: "*print-length* controls how many items of each collection the\n  printer will print. If it is bound to logical false, there is no\n  limit. Otherwise, it must be bound to an integer indicating the maximum\n  number of items of each collection to print. If a collection contains\n  more items, the printer will print items up to the limit followed by\n  '...' to represent the remaining items. The root binding is nil\n  indicating no limit.".to_string() },
        CoreSymbol { name: "*print-level*".to_string(), params: "".to_string(), doc: "*print-level* controls how many levels deep the printer will\n  print nested objects. If it is bound to logical false, there is no\n  limit. Otherwise, it must be bound to an integer indicating the maximum\n  level to print. Each argument to print is at level 0; if an argument is a\n  collection, its items are at level 1; and so on. If an object is a\n  collection and is at a level greater than or equal to the value bound to\n  *print-level*, the printer prints '#' to represent it. The root binding\n  is nil indicating no limit.".to_string() },
        CoreSymbol { name: "*print-meta*".to_string(), params: "".to_string(), doc: "If set to logical true, when printing an object, its metadata will also\n  be printed in a form that can be read back by the reader.\n\n  Defaults to false.".to_string() },
        CoreSymbol { name: "*print-namespace-maps*".to_string(), params: "".to_string(), doc: "*print-namespace-maps* controls whether the printer will print\n  namespace map literal syntax. It defaults to false, but the REPL binds\n  to true.".to_string() },
        CoreSymbol { name: "*print-readably*".to_string(), params: "".to_string(), doc: "When set to logical false, strings and characters will be printed with\n  non-alphanumeric characters converted to the appropriate escape sequences.\n\n  Defaults to true".to_string() },
        CoreSymbol { name: "*read-eval*".to_string(), params: "".to_string(), doc: "Defaults to true (or value specified by system property, see below)\n  ***This setting implies that the full power of the reader is in play,\n  including syntax that can cause code to execute. It should never be\n  used with untrusted sources. See also: clojure.edn/read.***\n\n  When set to logical false in the thread-local binding,\n  the eval reader (#=) and record/type literal syntax are disabled in read/load.\n  Example (will fail): (binding [*read-eval* false] (read-string \"#=(* 2 21)\"))\n\n  The default binding can be controlled by the system property\n  'clojure.read.eval' System properties can be set on the command line\n  like this:\n\n  java -Dclojure.read.eval=false ...\n\n  The system property can also be set to 'unknown' via\n  -Dclojure.read.eval=unknown, in which case the default binding\n  is :unknown and all reads will fail in contexts where *read-eval*\n  has not been explicitly bound to either true or false. This setting\n  can be a useful diagnostic tool to ensure that all of your reads\n  occur in considered contexts. You can also accomplish this in a\n  particular scope by binding *read-eval* to :unknown\n  ".to_string() },
        CoreSymbol { name: "*reader-resolver*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*unchecked-math*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "*warn-on-reflection*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "+".to_string(), params: "([] [x] [x y] [x y & more])".to_string(), doc: "Returns the sum of nums. (+) returns 0. Does not auto-promote\n  longs, will throw on overflow. See also: +'".to_string() },
        CoreSymbol { name: "+'".to_string(), params: "([] [x] [x y] [x y & more])".to_string(), doc: "Returns the sum of nums. (+') returns 0. Supports arbitrary precision.\n  See also: +".to_string() },
        CoreSymbol { name: "-".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "If no ys are supplied, returns the negation of x, else subtracts\n  the ys from x and returns the result. Does not auto-promote\n  longs, will throw on overflow. See also: -'".to_string() },
        CoreSymbol { name: "-'".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "If no ys are supplied, returns the negation of x, else subtracts\n  the ys from x and returns the result. Supports arbitrary precision.\n  See also: -".to_string() },
        CoreSymbol { name: "->".to_string(), params: "([x & forms])".to_string(), doc: "Threads the expr through the forms. Inserts x as the\n  second item in the first form, making a list of it if it is not a\n  list already. If there are more forms, inserts the first form as the\n  second item in second form, etc.".to_string() },
        CoreSymbol { name: "->>".to_string(), params: "([x & forms])".to_string(), doc: "Threads the expr through the forms. Inserts x as the\n  last item in the first form, making a list of it if it is not a\n  list already. If there are more forms, inserts the first form as the\n  last item in second form, etc.".to_string() },
        CoreSymbol { name: "->Eduction".to_string(), params: "([xform coll])".to_string(), doc: "Positional factory function for class clojure.core.Eduction.".to_string() },
        CoreSymbol { name: "-add-loaded-lib".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "-new-dynamic-var".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "-new-var".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "-reified-methods".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "-run-in-transaction".to_string(), params: "([f])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "-with-precision".to_string(), params: "([math-context body-fn])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "..".to_string(), params: "([x form] [x form & more])".to_string(), doc: "form => fieldName-symbol or (instanceMethodName-symbol args*)\n\n  Expands into a member access (.) of the first member on the first\n  argument, followed by the next member on the result, etc. For\n  instance:\n\n  (.. System (getProperties) (get \"os.name\"))\n\n  expands to:\n\n  (. (. System (getProperties)) (get \"os.name\"))\n\n  but is easier to write, read, and understand.".to_string() },
        CoreSymbol { name: "/".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "If no denominators are supplied, returns 1/numerator,\n  else returns numerator divided by all of the denominators.".to_string() },
        CoreSymbol { name: "<".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns non-nil if nums are in monotonically increasing order,\n  otherwise false.".to_string() },
        CoreSymbol { name: "<=".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns non-nil if nums are in monotonically non-decreasing order,\n  otherwise false.".to_string() },
        CoreSymbol { name: "=".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Equality. Returns true if x equals y, false if not. Same as\n  Java x.equals(y) except it also works for nil, and compares\n  numbers and collections in a type-independent manner.  Clojure's immutable data\n  structures define equals() (and thus =) as a value, not an identity,\n  comparison.".to_string() },
        CoreSymbol { name: "==".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns non-nil if nums all have the equivalent\n  value (type-independent), otherwise false".to_string() },
        CoreSymbol { name: ">".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns non-nil if nums are in monotonically decreasing order,\n  otherwise false.".to_string() },
        CoreSymbol { name: ">=".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns non-nil if nums are in monotonically non-increasing order,\n  otherwise false.".to_string() },
        CoreSymbol { name: "NaN?".to_string(), params: "([num])".to_string(), doc: "Returns true if num is NaN, else false".to_string() },
        CoreSymbol { name: "PrintWriter-on".to_string(), params: "([flush-fn close-fn])".to_string(), doc: "implements java.io.PrintWriter given flush-fn, which will be called\n  when .flush() is called, with a string built up since the last call to .flush().\n  if not nil, close-fn will be called with no arguments when .close is called".to_string() },
        CoreSymbol { name: "StackTraceElement->vec".to_string(), params: "([o])".to_string(), doc: "Constructs a data representation for a StackTraceElement: [class method file line]".to_string() },
        CoreSymbol { name: "Throwable->map".to_string(), params: "([o])".to_string(), doc: "Constructs a data representation for a Throwable with keys:\n    :cause - root cause message\n    :phase - error phase\n    :via - cause chain, with cause keys:\n             :type - exception class symbol\n             :message - exception message\n             :data - ex-data\n             :at - top stack element\n    :trace - root cause stack elements".to_string() },
        CoreSymbol { name: "abs".to_string(), params: "([a])".to_string(), doc: "Returns the absolute value of a.\n  If a is Long/MIN_VALUE => Long/MIN_VALUE\n  If a is a double and zero => +0.0\n  If a is a double and ##Inf or ##-Inf => ##Inf\n  If a is a double and ##NaN => ##NaN".to_string() },
        CoreSymbol { name: "aclone".to_string(), params: "([array])".to_string(), doc: "Returns a clone of the Java array. Works on arrays of known\n  types.".to_string() },
        CoreSymbol { name: "add-tap".to_string(), params: "([f])".to_string(), doc: "adds f, a fn of one argument, to the tap set. This function will be called with anything sent via tap>.\n  This function may (briefly) block (e.g. for streams), and will never impede calls to tap>,\n  but blocking indefinitely may cause tap values to be dropped.\n  Remember f in order to remove-tap".to_string() },
        CoreSymbol { name: "add-watch".to_string(), params: "([reference key fn])".to_string(), doc: "Adds a watch function to an agent/atom/var/ref reference. The watch\n  fn must be a fn of 4 args: a key, the reference, its old-state, its\n  new-state. Whenever the reference's state might have been changed,\n  any registered watches will have their functions called. The watch fn\n  will be called synchronously, on the agent's thread if an agent,\n  before any pending sends if agent or ref. Note that an atom's or\n  ref's state may have changed again prior to the fn call, so use\n  old/new-state rather than derefing the reference. Note also that watch\n  fns may be called from multiple threads simultaneously. Var watchers\n  are triggered only by root binding changes, not thread-local\n  set!s. Keys must be unique per reference, and can be used to remove\n  the watch with remove-watch, but are otherwise considered opaque by\n  the watch mechanism.".to_string() },
        CoreSymbol { name: "agent".to_string(), params: "([state & options])".to_string(), doc: "Creates and returns an agent with an initial value of state and\n  zero or more options (in any order):\n\n  :meta metadata-map\n\n  :validator validate-fn\n\n  :error-handler handler-fn\n\n  :error-mode mode-keyword\n\n  If metadata-map is supplied, it will become the metadata on the\n  agent. validate-fn must be nil or a side-effect-free fn of one\n  argument, which will be passed the intended new state on any state\n  change. If the new state is unacceptable, the validate-fn should\n  return false or throw an exception.  handler-fn is called if an\n  action throws an exception or if validate-fn rejects a new state --\n  see set-error-handler! for details.  The mode-keyword may be either\n  :continue (the default if an error-handler is given) or :fail (the\n  default if no error-handler is given) -- see set-error-mode! for\n  details.".to_string() },
        CoreSymbol { name: "agent-error".to_string(), params: "([a])".to_string(), doc: "Returns the exception thrown during an asynchronous action of the\n  agent if the agent is failed.  Returns nil if the agent is not\n  failed.".to_string() },
        CoreSymbol { name: "aget".to_string(), params: "([array idx] [array idx & idxs])".to_string(), doc: "Returns the value at the index/indices. Works on Java arrays of all\n  types.".to_string() },
        CoreSymbol { name: "alength".to_string(), params: "([array])".to_string(), doc: "Returns the length of the Java array. Works on arrays of all\n  types.".to_string() },
        CoreSymbol { name: "alias".to_string(), params: "([alias namespace-sym])".to_string(), doc: "Add an alias in the current namespace to another\n  namespace. Arguments are two symbols: the alias to be used, and\n  the symbolic name of the target namespace. Use :as in the ns macro in preference\n  to calling this directly.".to_string() },
        CoreSymbol { name: "all-ns".to_string(), params: "([])".to_string(), doc: "Returns a sequence of all namespaces.".to_string() },
        CoreSymbol { name: "alter".to_string(), params: "([ref fun & args])".to_string(), doc: "Must be called in a transaction. Sets the in-transaction-value of\n  ref to:\n\n  (apply fun in-transaction-value-of-ref args)\n\n  and returns the in-transaction-value of ref.".to_string() },
        CoreSymbol { name: "alter-meta!".to_string(), params: "([iref f & args])".to_string(), doc: "Atomically sets the metadata for a namespace/var/ref/agent/atom to be:\n\n  (apply f its-current-meta args)\n\n  f must be free of side-effects".to_string() },
        CoreSymbol { name: "alter-var-root".to_string(), params: "([v f & args])".to_string(), doc: "Atomically alters the root binding of var v by applying f to its\n  current value plus any args".to_string() },
        CoreSymbol { name: "amap".to_string(), params: "([a idx ret expr])".to_string(), doc: "Maps an expression across an array a, using an index named idx, and\n  return value named ret, initialized to a clone of a, then setting \n  each element of ret to the evaluation of expr, returning the new \n  array ret.".to_string() },
        CoreSymbol { name: "ancestors".to_string(), params: "([tag] [h tag])".to_string(), doc: "Returns the immediate and indirect parents of tag, either via a Java type\n  inheritance relationship or a relationship established via derive. h\n  must be a hierarchy obtained from make-hierarchy, if not supplied\n  defaults to the global hierarchy".to_string() },
        CoreSymbol { name: "and".to_string(), params: "([] [x] [x & next])".to_string(), doc: "Evaluates exprs one at a time, from left to right. If a form\n  returns logical false (nil or false), and returns that value and\n  doesn't evaluate any of the other expressions, otherwise it returns\n  the value of the last expr. (and) returns true.".to_string() },
        CoreSymbol { name: "any?".to_string(), params: "([x])".to_string(), doc: "Returns true given any argument.".to_string() },
        CoreSymbol { name: "apply".to_string(), params: "([f args] [f x args] [f x y args] [f x y z args] [f a b c d & args])".to_string(), doc: "Applies fn f to the argument list formed by prepending intervening arguments to args.".to_string() },
        CoreSymbol { name: "areduce".to_string(), params: "([a idx ret init expr])".to_string(), doc: "Reduces an expression across an array a, using an index named idx,\n  and return value named ret, initialized to init, setting ret to the \n  evaluation of expr at each step, returning ret.".to_string() },
        CoreSymbol { name: "array-map".to_string(), params: "([] [& keyvals])".to_string(), doc: "Constructs an array-map. If any keys are equal, they are handled as\n  if by repeated uses of assoc.".to_string() },
        CoreSymbol { name: "as->".to_string(), params: "([expr name & forms])".to_string(), doc: "Binds name to expr, evaluates the first form in the lexical context\n  of that binding, then binds name to that result, repeating for each\n  successive form, returning the result of the last form.".to_string() },
        CoreSymbol { name: "aset".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on Java arrays of\n  reference types. Returns val.".to_string() },
        CoreSymbol { name: "aset-boolean".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of boolean. Returns val.".to_string() },
        CoreSymbol { name: "aset-byte".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of byte. Returns val.".to_string() },
        CoreSymbol { name: "aset-char".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of char. Returns val.".to_string() },
        CoreSymbol { name: "aset-double".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of double. Returns val.".to_string() },
        CoreSymbol { name: "aset-float".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of float. Returns val.".to_string() },
        CoreSymbol { name: "aset-int".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of int. Returns val.".to_string() },
        CoreSymbol { name: "aset-long".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of long. Returns val.".to_string() },
        CoreSymbol { name: "aset-short".to_string(), params: "([array idx val] [array idx idx2 & idxv])".to_string(), doc: "Sets the value at the index/indices. Works on arrays of short. Returns val.".to_string() },
        CoreSymbol { name: "assert".to_string(), params: "([x] [x message])".to_string(), doc: "Evaluates expr and throws an exception if it does not evaluate to\n  logical true.".to_string() },
        CoreSymbol { name: "assoc".to_string(), params: "([map key val] [map key val & kvs])".to_string(), doc: "assoc[iate]. When applied to a map, returns a new map of the\n    same (hashed/sorted) type, that contains the mapping of key(s) to\n    val(s). When applied to a vector, returns a new vector that\n    contains val at index. Note - index must be <= (count vector).".to_string() },
        CoreSymbol { name: "assoc!".to_string(), params: "([coll key val] [coll key val & kvs])".to_string(), doc: "When applied to a transient map, adds mapping of key(s) to\n  val(s). When applied to a transient vector, sets the val at index.\n  Note - index must be <= (count vector). Returns coll.".to_string() },
        CoreSymbol { name: "assoc-in".to_string(), params: "([m [k & ks] v])".to_string(), doc: "Associates a value in a nested associative structure, where ks is a\n  sequence of keys and v is the new value and returns a new nested structure.\n  If any levels do not exist, hash-maps will be created.".to_string() },
        CoreSymbol { name: "associative?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll implements Associative".to_string() },
        CoreSymbol { name: "atom".to_string(), params: "([x] [x & options])".to_string(), doc: "Creates and returns an Atom with an initial value of x and zero or\n  more options (in any order):\n\n  :meta metadata-map\n\n  :validator validate-fn\n\n  If metadata-map is supplied, it will become the metadata on the\n  atom. validate-fn must be nil or a side-effect-free fn of one\n  argument, which will be passed the intended new state on any state\n  change. If the new state is unacceptable, the validate-fn should\n  return false or throw an exception.".to_string() },
        CoreSymbol { name: "await".to_string(), params: "([& agents])".to_string(), doc: "Blocks the current thread (indefinitely!) until all actions\n  dispatched thus far, from this thread or agent, to the agent(s) have\n  occurred.  Will block on failed agents.  Will never return if\n  a failed agent is restarted with :clear-actions true or shutdown-agents was called.".to_string() },
        CoreSymbol { name: "await-for".to_string(), params: "([timeout-ms & agents])".to_string(), doc: "Blocks the current thread until all actions dispatched thus\n  far (from this thread or agent) to the agents have occurred, or the\n  timeout (in milliseconds) has elapsed. Returns logical false if\n  returning due to timeout, logical true otherwise.".to_string() },
        CoreSymbol { name: "bean".to_string(), params: "([x])".to_string(), doc: "Takes a Java object and returns a read-only implementation of the\n  map abstraction based upon its JavaBean properties.".to_string() },
        CoreSymbol { name: "bigdec".to_string(), params: "([x])".to_string(), doc: "Coerce to BigDecimal".to_string() },
        CoreSymbol { name: "bigint".to_string(), params: "([x])".to_string(), doc: "Coerce to BigInt".to_string() },
        CoreSymbol { name: "biginteger".to_string(), params: "([x])".to_string(), doc: "Coerce to BigInteger".to_string() },
        CoreSymbol { name: "binding".to_string(), params: "([bindings & body])".to_string(), doc: "binding => var-symbol init-expr\n\n  Creates new bindings for the (already-existing) vars, with the\n  supplied initial values, executes the exprs in an implicit do, then\n  re-establishes the bindings that existed before.  The new bindings\n  are made in parallel (unlike let); all init-exprs are evaluated\n  before the vars are bound to their new values.".to_string() },
        CoreSymbol { name: "binding-conveyor-fn".to_string(), params: "([f])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "bit-and".to_string(), params: "([x y] [x y & more])".to_string(), doc: "Bitwise and".to_string() },
        CoreSymbol { name: "bit-and-not".to_string(), params: "([x y] [x y & more])".to_string(), doc: "Bitwise and with complement".to_string() },
        CoreSymbol { name: "bit-clear".to_string(), params: "([x n])".to_string(), doc: "Clear bit at index n".to_string() },
        CoreSymbol { name: "bit-flip".to_string(), params: "([x n])".to_string(), doc: "Flip bit at index n".to_string() },
        CoreSymbol { name: "bit-not".to_string(), params: "([x])".to_string(), doc: "Bitwise complement".to_string() },
        CoreSymbol { name: "bit-or".to_string(), params: "([x y] [x y & more])".to_string(), doc: "Bitwise or".to_string() },
        CoreSymbol { name: "bit-set".to_string(), params: "([x n])".to_string(), doc: "Set bit at index n".to_string() },
        CoreSymbol { name: "bit-shift-left".to_string(), params: "([x n])".to_string(), doc: "Bitwise shift left".to_string() },
        CoreSymbol { name: "bit-shift-right".to_string(), params: "([x n])".to_string(), doc: "Bitwise shift right".to_string() },
        CoreSymbol { name: "bit-test".to_string(), params: "([x n])".to_string(), doc: "Test bit at index n".to_string() },
        CoreSymbol { name: "bit-xor".to_string(), params: "([x y] [x y & more])".to_string(), doc: "Bitwise exclusive or".to_string() },
        CoreSymbol { name: "boolean".to_string(), params: "([x])".to_string(), doc: "Coerce to boolean".to_string() },
        CoreSymbol { name: "boolean-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of booleans".to_string() },
        CoreSymbol { name: "boolean?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a Boolean".to_string() },
        CoreSymbol { name: "booleans".to_string(), params: "([xs])".to_string(), doc: "Casts to boolean[]".to_string() },
        CoreSymbol { name: "bound-fn".to_string(), params: "([& fntail])".to_string(), doc: "Returns a function defined by the given fntail, which will install the\n  same bindings in effect as in the thread at the time bound-fn was called.\n  This may be used to define a helper function which runs on a different\n  thread, but needs the same bindings in place.".to_string() },
        CoreSymbol { name: "bound-fn*".to_string(), params: "([f])".to_string(), doc: "Returns a function, which will install the same bindings in effect as in\n  the thread at the time bound-fn* was called and then call f with any given\n  arguments. This may be used to define a helper function which runs on a\n  different thread, but needs the same bindings in place.".to_string() },
        CoreSymbol { name: "bound?".to_string(), params: "([& vars])".to_string(), doc: "Returns true if all of the vars provided as arguments have any bound value, root or thread-local.\n   Implies that deref'ing the provided vars will succeed. Returns true if no vars are provided.".to_string() },
        CoreSymbol { name: "bounded-count".to_string(), params: "([n coll])".to_string(), doc: "If coll is counted? returns its count, else will count at most the first n\n  elements of coll using its seq".to_string() },
        CoreSymbol { name: "butlast".to_string(), params: "([coll])".to_string(), doc: "Return a seq of all but the last item in coll, in linear time".to_string() },
        CoreSymbol { name: "byte".to_string(), params: "([x])".to_string(), doc: "Coerce to byte".to_string() },
        CoreSymbol { name: "byte-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of bytes".to_string() },
        CoreSymbol { name: "bytes".to_string(), params: "([xs])".to_string(), doc: "Casts to bytes[]".to_string() },
        CoreSymbol { name: "bytes?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a byte array".to_string() },
        CoreSymbol { name: "case".to_string(), params: "([e & clauses])".to_string(), doc: "Takes an expression, and a set of clauses.\n\n  Each clause can take the form of either:\n\n  test-constant result-expr\n\n  (test-constant1 ... test-constantN)  result-expr\n\n  The test-constants are not evaluated. They must be compile-time\n  literals, and need not be quoted.  If the expression is equal to a\n  test-constant, the corresponding result-expr is returned. A single\n  default expression can follow the clauses, and its value will be\n  returned if no clause matches. If no default expression is provided\n  and no clause matches, an IllegalArgumentException is thrown.\n\n  Unlike cond and condp, case does a constant-time dispatch, the\n  clauses are not considered sequentially.  All manner of constant\n  expressions are acceptable in case, including numbers, strings,\n  symbols, keywords, and (Clojure) composites thereof. Note that since\n  lists are used to group multiple constants that map to the same\n  expression, a vector can be used to match a list if needed. The\n  test-constants need not be all of the same type.".to_string() },
        CoreSymbol { name: "cat".to_string(), params: "([rf])".to_string(), doc: "A transducer which concatenates the contents of each input, which must be a\n  collection, into the reduction.".to_string() },
        CoreSymbol { name: "char".to_string(), params: "([x])".to_string(), doc: "Coerce to char".to_string() },
        CoreSymbol { name: "char-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of chars".to_string() },
        CoreSymbol { name: "char-escape-string".to_string(), params: "".to_string(), doc: "Returns escape string for char or nil if none".to_string() },
        CoreSymbol { name: "char-name-string".to_string(), params: "".to_string(), doc: "Returns name string for char or nil if none".to_string() },
        CoreSymbol { name: "char?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a Character".to_string() },
        CoreSymbol { name: "chars".to_string(), params: "([xs])".to_string(), doc: "Casts to chars[]".to_string() },
        CoreSymbol { name: "chunk".to_string(), params: "([b])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-append".to_string(), params: "([b x])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-buffer".to_string(), params: "([capacity])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-cons".to_string(), params: "([chunk rest])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-first".to_string(), params: "([s])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-next".to_string(), params: "([s])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunk-rest".to_string(), params: "([s])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "chunked-seq?".to_string(), params: "([s])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "class".to_string(), params: "([x])".to_string(), doc: "Returns the Class of x".to_string() },
        CoreSymbol { name: "class?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is an instance of Class".to_string() },
        CoreSymbol { name: "clojure-version".to_string(), params: "([])".to_string(), doc: "Returns clojure version as a printable string.".to_string() },
        CoreSymbol { name: "coll?".to_string(), params: "([x])".to_string(), doc: "Returns true if x implements IPersistentCollection".to_string() },
        CoreSymbol { name: "comment".to_string(), params: "([& body])".to_string(), doc: "Ignores body, yields nil".to_string() },
        CoreSymbol { name: "commute".to_string(), params: "([ref fun & args])".to_string(), doc: "Must be called in a transaction. Sets the in-transaction-value of\n  ref to:\n\n  (apply fun in-transaction-value-of-ref args)\n\n  and returns the in-transaction-value of ref.\n\n  At the commit point of the transaction, sets the value of ref to be:\n\n  (apply fun most-recently-committed-value-of-ref args)\n\n  Thus fun should be commutative, or, failing that, you must accept\n  last-one-in-wins behavior.  commute allows for more concurrency than\n  ref-set.".to_string() },
        CoreSymbol { name: "comp".to_string(), params: "([] [f] [f g] [f g & fs])".to_string(), doc: "Takes a set of functions and returns a fn that is the composition\n  of those fns.  The returned fn takes a variable number of args,\n  applies the rightmost of fns to the args, the next\n  fn (right-to-left) to the result, etc.".to_string() },
        CoreSymbol { name: "comparator".to_string(), params: "([pred])".to_string(), doc: "Returns an implementation of java.util.Comparator based upon pred.".to_string() },
        CoreSymbol { name: "compare".to_string(), params: "([x y])".to_string(), doc: "Comparator. Returns a negative number, zero, or a positive number\n  when x is logically 'less than', 'equal to', or 'greater than'\n  y. Same as Java x.compareTo(y) except it also works for nil, and\n  compares numbers and collections in a type-independent manner. x\n  must implement Comparable".to_string() },
        CoreSymbol { name: "compare-and-set!".to_string(), params: "([atom oldval newval])".to_string(), doc: "Atomically sets the value of atom to newval if and only if the\n  current value of the atom is identical to oldval. Returns true if\n  set happened, else false".to_string() },
        CoreSymbol { name: "complement".to_string(), params: "([f])".to_string(), doc: "Takes a fn f and returns a fn that takes the same arguments as f,\n  has the same effects, if any, and returns the opposite truth value.".to_string() },
        CoreSymbol { name: "completing".to_string(), params: "([f] [f cf])".to_string(), doc: "Takes a reducing function f of 2 args and returns a fn suitable for\n  transduce by adding an arity-1 signature that calls cf (default -\n  identity) on the result argument.".to_string() },
        CoreSymbol { name: "concat".to_string(), params: "([] [x] [x y] [x y & zs])".to_string(), doc: "Returns a lazy seq representing the concatenation of the elements in the supplied colls.".to_string() },
        CoreSymbol { name: "cond".to_string(), params: "([& clauses])".to_string(), doc: "Takes a set of test/expr pairs. It evaluates each test one at a\n  time.  If a test returns logical true, cond evaluates and returns\n  the value of the corresponding expr and doesn't evaluate any of the\n  other tests or exprs. (cond) returns nil.".to_string() },
        CoreSymbol { name: "cond->".to_string(), params: "([expr & clauses])".to_string(), doc: "Takes an expression and a set of test/form pairs. Threads expr (via ->)\n  through each form for which the corresponding test\n  expression is true. Note that, unlike cond branching, cond-> threading does\n  not short circuit after the first true test expression.".to_string() },
        CoreSymbol { name: "cond->>".to_string(), params: "([expr & clauses])".to_string(), doc: "Takes an expression and a set of test/form pairs. Threads expr (via ->>)\n  through each form for which the corresponding test expression\n  is true.  Note that, unlike cond branching, cond->> threading does not short circuit\n  after the first true test expression.".to_string() },
        CoreSymbol { name: "condp".to_string(), params: "([pred expr & clauses])".to_string(), doc: "Takes a binary predicate, an expression, and a set of clauses.\n  Each clause can take the form of either:\n\n  test-expr result-expr\n\n  test-expr :>> result-fn\n\n  Note :>> is an ordinary keyword.\n\n  For each clause, (pred test-expr expr) is evaluated. If it returns\n  logical true, the clause is a match. If a binary clause matches, the\n  result-expr is returned, if a ternary clause matches, its result-fn,\n  which must be a unary function, is called with the result of the\n  predicate as its argument, the result of that call being the return\n  value of condp. A single default expression can follow the clauses,\n  and its value will be returned if no clause matches. If no default\n  expression is provided and no clause matches, an\n  IllegalArgumentException is thrown.".to_string() },
        CoreSymbol { name: "conj".to_string(), params: "([] [coll] [coll x] [coll x & xs])".to_string(), doc: "conj[oin]. Returns a new collection with the xs\n    'added'. (conj nil item) returns (item).\n    (conj coll) returns coll. (conj) returns [].\n    The 'addition' may happen at different 'places' depending\n    on the concrete type.".to_string() },
        CoreSymbol { name: "conj!".to_string(), params: "([] [coll] [coll x])".to_string(), doc: "Adds x to the transient collection, and return coll. The 'addition'\n  may happen at different 'places' depending on the concrete type.".to_string() },
        CoreSymbol { name: "cons".to_string(), params: "([x seq])".to_string(), doc: "Returns a new seq where x is the first element and seq is\n    the rest.".to_string() },
        CoreSymbol { name: "constantly".to_string(), params: "([x])".to_string(), doc: "Returns a function that takes any number of arguments and returns x.".to_string() },
        CoreSymbol { name: "contains?".to_string(), params: "([coll key])".to_string(), doc: "Returns true if key is present in the given collection, otherwise\n  returns false.  Note that for numerically indexed collections like\n  vectors and Java arrays, this tests if the numeric key is within the\n  range of indexes. 'contains?' operates constant or logarithmic time;\n  it will not perform a linear search for a value.  See also 'some'.".to_string() },
        CoreSymbol { name: "count".to_string(), params: "([coll])".to_string(), doc: "Returns the number of items in the collection. (count nil) returns\n  0.  Also works on strings, arrays, and Java Collections and Maps".to_string() },
        CoreSymbol { name: "counted?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll implements count in constant time".to_string() },
        CoreSymbol { name: "create-ns".to_string(), params: "([sym])".to_string(), doc: "Create a new namespace named by the symbol if one doesn't already\n  exist, returns it or the already-existing namespace of the same\n  name.".to_string() },
        CoreSymbol { name: "cycle".to_string(), params: "([coll])".to_string(), doc: "Returns a lazy (infinite!) sequence of repetitions of the items in coll.".to_string() },
        CoreSymbol { name: "dec".to_string(), params: "([x])".to_string(), doc: "Returns a number one less than num. Does not auto-promote\n  longs, will throw on overflow. See also: dec'".to_string() },
        CoreSymbol { name: "dec'".to_string(), params: "([x])".to_string(), doc: "Returns a number one less than num. Supports arbitrary precision.\n  See also: dec".to_string() },
        CoreSymbol { name: "decimal?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is a BigDecimal".to_string() },
        CoreSymbol { name: "declare".to_string(), params: "([& names])".to_string(), doc: "defs the supplied var names with no bindings, useful for making forward declarations.".to_string() },
        CoreSymbol { name: "dedupe".to_string(), params: "([] [coll])".to_string(), doc: "Returns a lazy sequence removing consecutive duplicates in coll.\n  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "default-data-readers".to_string(), params: "".to_string(), doc: "Default map of data reader functions provided by Clojure. May be\n  overridden by binding *data-readers*.".to_string() },
        CoreSymbol { name: "defmacro".to_string(), params: "([name doc-string? attr-map? [params*] body] [name doc-string? attr-map? ([params*] body) + attr-map?])".to_string(), doc: "Like defn, but the resulting function name is declared as a\n  macro and will be used as a macro by the compiler when it is\n  called.".to_string() },
        CoreSymbol { name: "defmethod".to_string(), params: "([multifn dispatch-val & fn-tail])".to_string(), doc: "Creates and installs a new method of multimethod associated with dispatch-value. ".to_string() },
        CoreSymbol { name: "defmulti".to_string(), params: "([name docstring? attr-map? dispatch-fn & options])".to_string(), doc: "Creates a new multimethod with the associated dispatch function.\n  The docstring and attr-map are optional.\n\n  Options are key-value pairs and may be one of:\n\n  :default\n\n  The default dispatch value, defaults to :default\n\n  :hierarchy\n\n  The value used for hierarchical dispatch (e.g. ::square is-a ::shape)\n\n  Hierarchies are type-like relationships that do not depend upon type\n  inheritance. By default Clojure's multimethods dispatch off of a\n  global hierarchy map.  However, a hierarchy relationship can be\n  created with the derive function used to augment the root ancestor\n  created with make-hierarchy.\n\n  Multimethods expect the value of the hierarchy option to be supplied as\n  a reference type e.g. a var (i.e. via the Var-quote dispatch macro #'\n  or the var special form).".to_string() },
        CoreSymbol { name: "defn".to_string(), params: "([name doc-string? attr-map? [params*] prepost-map? body] [name doc-string? attr-map? ([params*] prepost-map? body) + attr-map?])".to_string(), doc: "Same as (def name (fn [params* ] exprs*)) or (def\n    name (fn ([params* ] exprs*)+)) with any doc-string or attrs added\n    to the var metadata. prepost-map defines a map with optional keys\n    :pre and :post that contain collections of pre or post conditions.".to_string() },
        CoreSymbol { name: "defn-".to_string(), params: "([name & decls])".to_string(), doc: "same as defn, yielding non-public def".to_string() },
        CoreSymbol { name: "defonce".to_string(), params: "([name expr])".to_string(), doc: "defs name to have the root value of the expr iff the named var has no root value,\n  else expr is unevaluated".to_string() },
        CoreSymbol { name: "defprotocol".to_string(), params: "([name & opts+sigs])".to_string(), doc: "A protocol is a named set of named methods and their signatures:\n  (defprotocol AProtocolName\n\n    ;optional doc string\n    \"A doc string for AProtocol abstraction\"\n\n   ;options\n   :extend-via-metadata true\n\n  ;method signatures\n    (bar [this a b] \"bar docs\")\n    (baz [this a] [this a b] [this a b c] \"baz docs\"))\n\n  No implementations are provided. Docs can be specified for the\n  protocol overall and for each method. The above yields a set of\n  polymorphic functions and a protocol object. All are\n  namespace-qualified by the ns enclosing the definition The resulting\n  functions dispatch on the type of their first argument, which is\n  required and corresponds to the implicit target object ('this' in \n  Java parlance). defprotocol is dynamic, has no special compile-time \n  effect, and defines no new types or classes. Implementations of \n  the protocol methods can be provided using extend.\n\n  When :extend-via-metadata is true, values can extend protocols by\n  adding metadata where keys are fully-qualified protocol function\n  symbols and values are function implementations. Protocol\n  implementations are checked first for direct definitions (defrecord,\n  deftype, reify), then metadata definitions, then external\n  extensions (extend, extend-type, extend-protocol)\n\n  defprotocol will automatically generate a corresponding interface,\n  with the same name as the protocol, i.e. given a protocol:\n  my.ns/Protocol, an interface: my.ns.Protocol. The interface will\n  have methods corresponding to the protocol functions, and the\n  protocol will automatically work with instances of the interface.\n\n  Note that you should not use this interface with deftype or\n  reify, as they support the protocol directly:\n\n  (defprotocol P \n    (foo [this]) \n    (bar-me [this] [this y]))\n\n  (deftype Foo [a b c] \n   P\n    (foo [this] a)\n    (bar-me [this] b)\n    (bar-me [this y] (+ c y)))\n  \n  (bar-me (Foo. 1 2 3) 42)\n  => 45\n\n  (foo \n    (let [x 42]\n      (reify P \n        (foo [this] 17)\n        (bar-me [this] x)\n        (bar-me [this y] x))))\n  => 17".to_string() },
        CoreSymbol { name: "defrecord".to_string(), params: "([name [& fields] & opts+specs])".to_string(), doc: "(defrecord name [fields*]  options* specs*)\n\n  Options are expressed as sequential keywords and arguments (in any order).\n\n  Supported options:\n  :load-ns - if true, importing the record class will cause the\n             namespace in which the record was defined to be loaded.\n             Defaults to false.\n\n  Each spec consists of a protocol or interface name followed by zero\n  or more method bodies:\n\n  protocol-or-interface-or-Object\n  (methodName [args*] body)*\n\n  Dynamically generates compiled bytecode for class with the given\n  name, in a package with the same name as the current namespace, the\n  given fields, and, optionally, methods for protocols and/or\n  interfaces.\n\n  The class will have the (immutable) fields named by\n  fields, which can have type hints. Protocols/interfaces and methods\n  are optional. The only methods that can be supplied are those\n  declared in the protocols/interfaces.  Note that method bodies are\n  not closures, the local environment includes only the named fields,\n  and those fields can be accessed directly.\n\n  Method definitions take the form:\n\n  (methodname [args*] body)\n\n  The argument and return types can be hinted on the arg and\n  methodname symbols. If not supplied, they will be inferred, so type\n  hints should be reserved for disambiguation.\n\n  Methods should be supplied for all methods of the desired\n  protocol(s) and interface(s). You can also define overrides for\n  methods of Object. Note that a parameter must be supplied to\n  correspond to the target object ('this' in Java parlance). Thus\n  methods for interfaces will take one more argument than do the\n  interface declarations. Note also that recur calls to the method\n  head should *not* pass the target object, it will be supplied\n  automatically and can not be substituted.\n\n  In the method bodies, the (unqualified) name can be used to name the\n  class (for calls to new, instance? etc).\n\n  The class will have implementations of several (clojure.lang)\n  interfaces generated automatically: IObj (metadata support) and\n  IPersistentMap, and all of their superinterfaces.\n\n  In addition, defrecord will define type-and-value-based =,\n  and will defined Java .hashCode and .equals consistent with the\n  contract for java.util.Map.\n\n  When AOT compiling, generates compiled bytecode for a class with the\n  given name (a symbol), prepends the current ns as the package, and\n  writes the .class file to the *compile-path* directory.\n\n  Two constructors will be defined, one taking the designated fields\n  followed by a metadata map (nil for none) and an extension field\n  map (nil for none), and one taking only the fields (using nil for\n  meta and extension fields). Note that the field names __meta,\n  __extmap, __hash and __hasheq are currently reserved and should not\n  be used when defining your own records.\n\n  Given (defrecord TypeName ...), two factory functions will be\n  defined: ->TypeName, taking positional parameters for the fields,\n  and map->TypeName, taking a map of keywords to field values.".to_string() },
        CoreSymbol { name: "deftype".to_string(), params: "([name [& fields] & opts+specs])".to_string(), doc: "(deftype name [fields*]  options* specs*)\n\n  Options are expressed as sequential keywords and arguments (in any order).\n\n  Supported options:\n  :load-ns - if true, importing the type class will cause the\n             namespace in which the type was defined to be loaded.\n             Defaults to false.\n\n  Each spec consists of a protocol or interface name followed by zero\n  or more method bodies:\n\n  protocol-or-interface-or-Object\n  (methodName [args*] body)*\n\n  Dynamically generates compiled bytecode for class with the given\n  name, in a package with the same name as the current namespace, the\n  given fields, and, optionally, methods for protocols and/or\n  interfaces. \n\n  The class will have the (by default, immutable) fields named by\n  fields, which can have type hints. Protocols/interfaces and methods\n  are optional. The only methods that can be supplied are those\n  declared in the protocols/interfaces.  Note that method bodies are\n  not closures, the local environment includes only the named fields,\n  and those fields can be accessed directly. Fields can be qualified\n  with the metadata :volatile-mutable true or :unsynchronized-mutable\n  true, at which point (set! afield aval) will be supported in method\n  bodies. Note well that mutable fields are extremely difficult to use\n  correctly, and are present only to facilitate the building of higher\n  level constructs, such as Clojure's reference types, in Clojure\n  itself. They are for experts only - if the semantics and\n  implications of :volatile-mutable or :unsynchronized-mutable are not\n  immediately apparent to you, you should not be using them.\n\n  Method definitions take the form:\n\n  (methodname [args*] body)\n\n  The argument and return types can be hinted on the arg and\n  methodname symbols. If not supplied, they will be inferred, so type\n  hints should be reserved for disambiguation.\n\n  Methods should be supplied for all methods of the desired\n  protocol(s) and interface(s). You can also define overrides for\n  methods of Object. Note that a parameter must be supplied to\n  correspond to the target object ('this' in Java parlance). Thus\n  methods for interfaces will take one more argument than do the\n  interface declarations. Note also that recur calls to the method\n  head should *not* pass the target object, it will be supplied\n  automatically and can not be substituted.\n\n  In the method bodies, the (unqualified) name can be used to name the\n  class (for calls to new, instance? etc).\n\n  When AOT compiling, generates compiled bytecode for a class with the\n  given name (a symbol), prepends the current ns as the package, and\n  writes the .class file to the *compile-path* directory.\n\n  One constructor will be defined, taking the designated fields.  Note\n  that the field names __meta, __extmap, __hash and __hasheq are currently\n  reserved and should not be used when defining your own types.\n\n  Given (deftype TypeName ...), a factory function called ->TypeName\n  will be defined, taking positional parameters for the fields".to_string() },
        CoreSymbol { name: "delay".to_string(), params: "([& body])".to_string(), doc: "Takes a body of expressions and yields a Delay object that will\n  invoke the body only the first time it is forced (with force or deref/@), and\n  will cache the result and return it on all subsequent force\n  calls. See also - realized?".to_string() },
        CoreSymbol { name: "delay?".to_string(), params: "([x])".to_string(), doc: "returns true if x is a Delay created with delay".to_string() },
        CoreSymbol { name: "deliver".to_string(), params: "([promise val])".to_string(), doc: "Delivers the supplied value to the promise, releasing any pending\n  derefs. A subsequent call to deliver on a promise will have no effect.".to_string() },
        CoreSymbol { name: "denominator".to_string(), params: "([r])".to_string(), doc: "Returns the denominator part of a Ratio.".to_string() },
        CoreSymbol { name: "deref".to_string(), params: "([ref] [ref timeout-ms timeout-val])".to_string(), doc: "Also reader macro: @ref/@agent/@var/@atom/@delay/@future/@promise. Within a transaction,\n  returns the in-transaction-value of ref, else returns the\n  most-recently-committed value of ref. When applied to a var, agent\n  or atom, returns its current state. When applied to a delay, forces\n  it if not already forced. When applied to a future, will block if\n  computation not complete. When applied to a promise, will block\n  until a value is delivered.  The variant taking a timeout can be\n  used for blocking references (futures and promises), and will return\n  timeout-val if the timeout (in milliseconds) is reached before a\n  value is available. See also - realized?.".to_string() },
        CoreSymbol { name: "derive".to_string(), params: "([tag parent] [h tag parent])".to_string(), doc: "Establishes a parent/child relationship between parent and\n  tag. Parent must be a namespace-qualified symbol or keyword and\n  child can be either a namespace-qualified symbol or keyword or a\n  class. h must be a hierarchy obtained from make-hierarchy, if not\n  supplied defaults to, and modifies, the global hierarchy.".to_string() },
        CoreSymbol { name: "descendants".to_string(), params: "([tag] [h tag])".to_string(), doc: "Returns the immediate and indirect children of tag, through a\n  relationship established via derive. h must be a hierarchy obtained\n  from make-hierarchy, if not supplied defaults to the global\n  hierarchy. Note: does not work on Java type inheritance\n  relationships.".to_string() },
        CoreSymbol { name: "disj".to_string(), params: "([set] [set key] [set key & ks])".to_string(), doc: "disj[oin]. Returns a new set of the same (hashed/sorted) type, that\n  does not contain key(s).".to_string() },
        CoreSymbol { name: "disj!".to_string(), params: "([set] [set key] [set key & ks])".to_string(), doc: "disj[oin]. Returns a transient set of the same (hashed/sorted) type, that\n  does not contain key(s).".to_string() },
        CoreSymbol { name: "dissoc".to_string(), params: "([map] [map key] [map key & ks])".to_string(), doc: "dissoc[iate]. Returns a new map of the same (hashed/sorted) type,\n  that does not contain a mapping for key(s).".to_string() },
        CoreSymbol { name: "dissoc!".to_string(), params: "([map key] [map key & ks])".to_string(), doc: "Returns a transient map that doesn't contain a mapping for key(s).".to_string() },
        CoreSymbol { name: "distinct".to_string(), params: "([] [coll])".to_string(), doc: "Returns a lazy sequence of the elements of coll with duplicates removed.\n  Returns a stateful transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "distinct?".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns true if no two of the arguments are =".to_string() },
        CoreSymbol { name: "doall".to_string(), params: "([coll] [n coll])".to_string(), doc: "When lazy sequences are produced via functions that have side\n  effects, any effects other than those needed to produce the first\n  element in the seq do not occur until the seq is consumed. doall can\n  be used to force any effects. Walks through the successive nexts of\n  the seq, retains the head and returns it, thus causing the entire\n  seq to reside in memory at one time.".to_string() },
        CoreSymbol { name: "dorun".to_string(), params: "([coll] [n coll])".to_string(), doc: "When lazy sequences are produced via functions that have side\n  effects, any effects other than those needed to produce the first\n  element in the seq do not occur until the seq is consumed. dorun can\n  be used to force any effects. Walks through the successive nexts of\n  the seq, does not retain the head and returns nil.".to_string() },
        CoreSymbol { name: "doseq".to_string(), params: "([seq-exprs & body])".to_string(), doc: "Repeatedly executes body (presumably for side-effects) with\n  bindings and filtering as provided by \"for\".  Does not retain\n  the head of the sequence. Returns nil.".to_string() },
        CoreSymbol { name: "dosync".to_string(), params: "([& exprs])".to_string(), doc: "Runs the exprs (in an implicit do) in a transaction that encompasses\n  exprs and any nested calls.  Starts a transaction if none is already\n  running on this thread. Any uncaught exception will abort the\n  transaction and flow out of dosync. The exprs may be run more than\n  once, but any effects on Refs will be atomic.".to_string() },
        CoreSymbol { name: "dotimes".to_string(), params: "([bindings & body])".to_string(), doc: "bindings => name n\n\n  Repeatedly executes body (presumably for side-effects) with name\n  bound to integers from 0 through n-1.".to_string() },
        CoreSymbol { name: "doto".to_string(), params: "([x & forms])".to_string(), doc: "Evaluates x then calls all of the methods and functions with the\n  value of x supplied at the front of the given arguments.  The forms\n  are evaluated in order.  Returns x.\n\n  (doto (new java.util.HashMap) (.put \"a\" 1) (.put \"b\" 2))".to_string() },
        CoreSymbol { name: "double".to_string(), params: "([x])".to_string(), doc: "Coerce to double".to_string() },
        CoreSymbol { name: "double-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of doubles".to_string() },
        CoreSymbol { name: "double?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a Double".to_string() },
        CoreSymbol { name: "doubles".to_string(), params: "([xs])".to_string(), doc: "Casts to double[]".to_string() },
        CoreSymbol { name: "drop".to_string(), params: "([n] [n coll])".to_string(), doc: "Returns a lazy sequence of all but the first n items in coll.\n  Returns a stateful transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "drop-last".to_string(), params: "([coll] [n coll])".to_string(), doc: "Return a lazy sequence of all but the last n (default 1) items in coll".to_string() },
        CoreSymbol { name: "drop-while".to_string(), params: "([pred] [pred coll])".to_string(), doc: "Returns a lazy sequence of the items in coll starting from the\n  first item for which (pred item) returns logical false.  Returns a\n  stateful transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "eduction".to_string(), params: "([xform* coll])".to_string(), doc: "Returns a reducible/iterable application of the transducers\n  to the items in coll. Transducers are applied in order as if\n  combined with comp. Note that these applications will be\n  performed every time reduce/iterator is called.".to_string() },
        CoreSymbol { name: "empty".to_string(), params: "([coll])".to_string(), doc: "Returns an empty collection of the same category as coll, or nil".to_string() },
        CoreSymbol { name: "empty?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll has no items - same as (not (seq coll)).\n  Please use the idiom (seq x) rather than (not (empty? x))".to_string() },
        CoreSymbol { name: "ensure-reduced".to_string(), params: "([x])".to_string(), doc: "If x is already reduced?, returns it, else returns (reduced x)".to_string() },
        CoreSymbol { name: "enumeration-seq".to_string(), params: "([e])".to_string(), doc: "Returns a seq on a java.util.Enumeration".to_string() },
        CoreSymbol { name: "error-handler".to_string(), params: "([a])".to_string(), doc: "Returns the error-handler of agent a, or nil if there is none.\n  See set-error-handler!".to_string() },
        CoreSymbol { name: "error-mode".to_string(), params: "([a])".to_string(), doc: "Returns the error-mode of agent a.  See set-error-mode!".to_string() },
        CoreSymbol { name: "eval".to_string(), params: "([form])".to_string(), doc: "Evaluates the form data structure (not text!) and returns the result.".to_string() },
        CoreSymbol { name: "even?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is even, throws an exception if n is not an integer".to_string() },
        CoreSymbol { name: "every-pred".to_string(), params: "([p] [p1 p2] [p1 p2 p3] [p1 p2 p3 & ps])".to_string(), doc: "Takes a set of predicates and returns a function f that returns true if all of its\n  composing predicates return a logical true value against all of its arguments, else it returns\n  false. Note that f is short-circuiting in that it will stop execution on the first\n  argument that triggers a logical false result against the original predicates.".to_string() },
        CoreSymbol { name: "every?".to_string(), params: "([pred coll])".to_string(), doc: "Returns true if (pred x) is logical true for every x in coll, else\n  false.".to_string() },
        CoreSymbol { name: "ex-cause".to_string(), params: "([ex])".to_string(), doc: "Returns the cause of ex if ex is a Throwable.\n  Otherwise returns nil.".to_string() },
        CoreSymbol { name: "ex-data".to_string(), params: "([ex])".to_string(), doc: "Returns exception data (a map) if ex is an IExceptionInfo.\n   Otherwise returns nil.".to_string() },
        CoreSymbol { name: "ex-info".to_string(), params: "([msg map] [msg map cause])".to_string(), doc: "Create an instance of ExceptionInfo, a RuntimeException subclass\n   that carries a map of additional data.".to_string() },
        CoreSymbol { name: "ex-message".to_string(), params: "([ex])".to_string(), doc: "Returns the message attached to ex if ex is a Throwable.\n  Otherwise returns nil.".to_string() },
        CoreSymbol { name: "extend".to_string(), params: "([atype & proto+mmaps])".to_string(), doc: "Implementations of protocol methods can be provided using the extend construct:\n\n  (extend AType\n    AProtocol\n     {:foo an-existing-fn\n      :bar (fn [a b] ...)\n      :baz (fn ([a]...) ([a b] ...)...)}\n    BProtocol \n      {...} \n    ...)\n \n  extend takes a type/class (or interface, see below), and one or more\n  protocol + method map pairs. It will extend the polymorphism of the\n  protocol's methods to call the supplied methods when an AType is\n  provided as the first argument. \n\n  Method maps are maps of the keyword-ized method names to ordinary\n  fns. This facilitates easy reuse of existing fns and fn maps, for\n  code reuse/mixins without derivation or composition. You can extend\n  an interface to a protocol. This is primarily to facilitate interop\n  with the host (e.g. Java) but opens the door to incidental multiple\n  inheritance of implementation since a class can inherit from more\n  than one interface, both of which extend the protocol. It is TBD how\n  to specify which impl to use. You can extend a protocol on nil.\n\n  If you are supplying the definitions explicitly (i.e. not reusing\n  exsting functions or mixin maps), you may find it more convenient to\n  use the extend-type or extend-protocol macros.\n\n  Note that multiple independent extend clauses can exist for the same\n  type, not all protocols need be defined in a single extend call.\n\n  See also:\n  extends?, satisfies?, extenders".to_string() },
        CoreSymbol { name: "extend-protocol".to_string(), params: "([p & specs])".to_string(), doc: "Useful when you want to provide several implementations of the same\n  protocol all at once. Takes a single protocol and the implementation\n  of that protocol for one or more types. Expands into calls to\n  extend-type:\n\n  (extend-protocol Protocol\n    AType\n      (foo [x] ...)\n      (bar [x y] ...)\n    BType\n      (foo [x] ...)\n      (bar [x y] ...)\n    AClass\n      (foo [x] ...)\n      (bar [x y] ...)\n    nil\n      (foo [x] ...)\n      (bar [x y] ...))\n\n  expands into:\n\n  (do\n   (clojure.core/extend-type AType Protocol \n     (foo [x] ...) \n     (bar [x y] ...))\n   (clojure.core/extend-type BType Protocol \n     (foo [x] ...) \n     (bar [x y] ...))\n   (clojure.core/extend-type AClass Protocol \n     (foo [x] ...) \n     (bar [x y] ...))\n   (clojure.core/extend-type nil Protocol \n     (foo [x] ...) \n     (bar [x y] ...)))".to_string() },
        CoreSymbol { name: "extend-type".to_string(), params: "([t & specs])".to_string(), doc: "A macro that expands into an extend call. Useful when you are\n  supplying the definitions explicitly inline, extend-type\n  automatically creates the maps required by extend.  Propagates the\n  class as a type hint on the first argument of all fns.\n\n  (extend-type MyType \n    Countable\n      (cnt [c] ...)\n    Foo\n      (bar [x y] ...)\n      (baz ([x] ...) ([x y & zs] ...)))\n\n  expands into:\n\n  (extend MyType\n   Countable\n     {:cnt (fn [c] ...)}\n   Foo\n     {:baz (fn ([x] ...) ([x y & zs] ...))\n      :bar (fn [x y] ...)})".to_string() },
        CoreSymbol { name: "extends?".to_string(), params: "([protocol atype])".to_string(), doc: "Returns true if atype extends protocol".to_string() },
        CoreSymbol { name: "false?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is the value false, false otherwise.".to_string() },
        CoreSymbol { name: "ffirst".to_string(), params: "([x])".to_string(), doc: "Same as (first (first x))".to_string() },
        CoreSymbol { name: "file-seq".to_string(), params: "([dir])".to_string(), doc: "A tree seq on java.io.Files".to_string() },
        CoreSymbol { name: "filter".to_string(), params: "([pred] [pred coll])".to_string(), doc: "Returns a lazy sequence of the items in coll for which\n  (pred item) returns logical true. pred must be free of side-effects.\n  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "filterv".to_string(), params: "([pred coll])".to_string(), doc: "Returns a vector of the items in coll for which\n  (pred item) returns logical true. pred must be free of side-effects.".to_string() },
        CoreSymbol { name: "find".to_string(), params: "([map key])".to_string(), doc: "Returns the map entry for key, or nil if key not present.".to_string() },
        CoreSymbol { name: "find-ns".to_string(), params: "([sym])".to_string(), doc: "Returns the namespace named by the symbol or nil if it doesn't exist.".to_string() },
        CoreSymbol { name: "find-var".to_string(), params: "([sym])".to_string(), doc: "Returns the global var named by the namespace-qualified symbol, or\n  nil if no var with that name.".to_string() },
        CoreSymbol { name: "first".to_string(), params: "([coll])".to_string(), doc: "Returns the first item in the collection. Calls seq on its\n    argument. If coll is nil, returns nil.".to_string() },
        CoreSymbol { name: "flatten".to_string(), params: "([x])".to_string(), doc: "Takes any nested combination of sequential things (lists, vectors,\n  etc.) and returns their contents as a single, flat lazy sequence.\n  (flatten nil) returns an empty sequence.".to_string() },
        CoreSymbol { name: "float".to_string(), params: "([x])".to_string(), doc: "Coerce to float".to_string() },
        CoreSymbol { name: "float-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of floats".to_string() },
        CoreSymbol { name: "float?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is a floating point number".to_string() },
        CoreSymbol { name: "floats".to_string(), params: "([xs])".to_string(), doc: "Casts to float[]".to_string() },
        CoreSymbol { name: "flush".to_string(), params: "([])".to_string(), doc: "Flushes the output stream that is the current value of\n  *out*".to_string() },
        CoreSymbol { name: "fn".to_string(), params: "([& sigs])".to_string(), doc: "params => positional-params*, or positional-params* & rest-param\n  positional-param => binding-form\n  rest-param => binding-form\n  binding-form => name, or destructuring-form\n\n  Defines a function.\n\n  See https://clojure.org/reference/special_forms#fn for more information".to_string() },
        CoreSymbol { name: "fn?".to_string(), params: "([x])".to_string(), doc: "Returns true if x implements Fn, i.e. is an object created via fn.".to_string() },
        CoreSymbol { name: "fnext".to_string(), params: "([x])".to_string(), doc: "Same as (first (next x))".to_string() },
        CoreSymbol { name: "fnil".to_string(), params: "([f x] [f x y] [f x y z])".to_string(), doc: "Takes a function f, and returns a function that calls f, replacing\n  a nil first argument to f with the supplied value x. Higher arity\n  versions can replace arguments in the second and third\n  positions (y, z). Note that the function f can take any number of\n  arguments, not just the one(s) being nil-patched.".to_string() },
        CoreSymbol { name: "for".to_string(), params: "([seq-exprs body-expr])".to_string(), doc: "List comprehension. Takes a vector of one or more\n   binding-form/collection-expr pairs, each followed by zero or more\n   modifiers, and yields a lazy sequence of evaluations of expr.\n   Collections are iterated in a nested fashion, rightmost fastest,\n   and nested coll-exprs can refer to bindings created in prior\n   binding-forms.  Supported modifiers are: :let [binding-form expr ...],\n   :while test, :when test.\n\n  (take 100 (for [x (range 100000000) y (range 1000000) :while (< y x)] [x y]))".to_string() },
        CoreSymbol { name: "force".to_string(), params: "([x])".to_string(), doc: "If x is a Delay, returns the (possibly cached) value of its expression, else returns x".to_string() },
        CoreSymbol { name: "format".to_string(), params: "([fmt & args])".to_string(), doc: "Formats a string using java.lang.String.format, see java.util.Formatter for format\n  string syntax".to_string() },
        CoreSymbol { name: "frequencies".to_string(), params: "([coll])".to_string(), doc: "Returns a map from distinct items in coll to the number of times\n  they appear.".to_string() },
        CoreSymbol { name: "future".to_string(), params: "([& body])".to_string(), doc: "Takes a body of expressions and yields a future object that will\n  invoke the body in another thread, and will cache the result and\n  return it on all subsequent calls to deref/@. If the computation has\n  not yet finished, calls to deref/@ will block, unless the variant of\n  deref with timeout is used. See also - realized?.".to_string() },
        CoreSymbol { name: "future-call".to_string(), params: "([f])".to_string(), doc: "Takes a function of no args and yields a future object that will\n  invoke the function in another thread, and will cache the result and\n  return it on all subsequent calls to deref/@. If the computation has\n  not yet finished, calls to deref/@ will block, unless the variant\n  of deref with timeout is used. See also - realized?.".to_string() },
        CoreSymbol { name: "future-cancel".to_string(), params: "([f])".to_string(), doc: "Cancels the future, if possible.".to_string() },
        CoreSymbol { name: "future-cancelled?".to_string(), params: "([f])".to_string(), doc: "Returns true if future f is cancelled".to_string() },
        CoreSymbol { name: "future-done?".to_string(), params: "([f])".to_string(), doc: "Returns true if future f is done".to_string() },
        CoreSymbol { name: "future?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is a future".to_string() },
        CoreSymbol { name: "gensym".to_string(), params: "([] [prefix-string])".to_string(), doc: "Returns a new symbol with a unique name. If a prefix string is\n  supplied, the name is prefix# where # is some unique number. If\n  prefix is not supplied, the prefix is 'G__'.".to_string() },
        CoreSymbol { name: "get".to_string(), params: "([map key] [map key not-found])".to_string(), doc: "Returns the value mapped to key, not-found or nil if key not present\n  in associative collection, set, string, array, or ILookup instance.".to_string() },
        CoreSymbol { name: "get-in".to_string(), params: "([m ks] [m ks not-found])".to_string(), doc: "Returns the value in a nested associative structure,\n  where ks is a sequence of keys. Returns nil if the key\n  is not present, or the not-found value if supplied.".to_string() },
        CoreSymbol { name: "get-method".to_string(), params: "([multifn dispatch-val])".to_string(), doc: "Given a multimethod and a dispatch value, returns the dispatch fn\n  that would apply to that value, or nil if none apply and no default".to_string() },
        CoreSymbol { name: "get-thread-binding-frame-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "get-thread-bindings".to_string(), params: "([])".to_string(), doc: "Get a map with the Var/value pairs which is currently in effect for the\n  current thread.".to_string() },
        CoreSymbol { name: "get-validator".to_string(), params: "([iref])".to_string(), doc: "Gets the validator-fn for a var/ref/agent/atom.".to_string() },
        CoreSymbol { name: "global-hierarchy".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "group-by".to_string(), params: "([f coll])".to_string(), doc: "Returns a map of the elements of coll keyed by the result of\n  f on each element. The value at each key will be a vector of the\n  corresponding elements, in the order they appeared in coll.".to_string() },
        CoreSymbol { name: "halt-when".to_string(), params: "([pred] [pred retf])".to_string(), doc: "Returns a transducer that ends transduction when pred returns true\n  for an input. When retf is supplied it must be a fn of 2 arguments -\n  it will be passed the (completed) result so far and the input that\n  triggered the predicate, and its return value (if it does not throw\n  an exception) will be the return value of the transducer. If retf\n  is not supplied, the input that triggered the predicate will be\n  returned. If the predicate never returns true the transduction is\n  unaffected.".to_string() },
        CoreSymbol { name: "has-root-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "hash".to_string(), params: "([x])".to_string(), doc: "Returns the hash code of its argument. Note this is the hash code\n  consistent with =, and thus is different than .hashCode for Integer,\n  Short, Byte and Clojure collections.".to_string() },
        CoreSymbol { name: "hash-combine".to_string(), params: "([x y])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "hash-map".to_string(), params: "([] [& keyvals])".to_string(), doc: "keyval => key val\n  Returns a new hash map with supplied mappings.  If any keys are\n  equal, they are handled as if by repeated uses of assoc.".to_string() },
        CoreSymbol { name: "hash-set".to_string(), params: "([] [& keys])".to_string(), doc: "Returns a new hash set with supplied keys.  Any equal keys are\n  handled as if by repeated uses of conj.".to_string() },
        CoreSymbol { name: "hash-unordered-coll".to_string(), params: "([coll])".to_string(), doc: "Returns the hash code, consistent with =, for an external unordered\n   collection implementing Iterable. For maps, the iterator should\n   return map entries whose hash is computed as\n     (hash-ordered-coll [k v]).\n   See http://clojure.org/data_structures#hash for full algorithms.".to_string() },
        CoreSymbol { name: "ident?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a symbol or keyword".to_string() },
        CoreSymbol { name: "identical?".to_string(), params: "([x y])".to_string(), doc: "Tests if 2 arguments are the same object".to_string() },
        CoreSymbol { name: "identity".to_string(), params: "([x])".to_string(), doc: "Returns its argument.".to_string() },
        CoreSymbol { name: "if-let".to_string(), params: "([bindings then] [bindings then else & oldform])".to_string(), doc: "bindings => binding-form test\n\n  If test is true, evaluates then with binding-form bound to the value of \n  test, if not, yields else".to_string() },
        CoreSymbol { name: "if-not".to_string(), params: "([test then] [test then else])".to_string(), doc: "Evaluates test. If logical false, evaluates and returns then expr, \n  otherwise else expr, if supplied, else nil.".to_string() },
        CoreSymbol { name: "if-some".to_string(), params: "([bindings then] [bindings then else & oldform])".to_string(), doc: "bindings => binding-form test\n\n   If test is not nil, evaluates then with binding-form bound to the\n   value of test, if not, yields else".to_string() },
        CoreSymbol { name: "ifn?".to_string(), params: "([x])".to_string(), doc: "Returns true if x implements IFn. Note that many data structures\n  (e.g. sets and maps) implement IFn".to_string() },
        CoreSymbol { name: "in-ns".to_string(), params: "([name])".to_string(), doc: "Sets *ns* to the namespace named by the symbol, creating it if needed.".to_string() },
        CoreSymbol { name: "inc".to_string(), params: "([x])".to_string(), doc: "Returns a number one greater than num. Does not auto-promote\n  longs, will throw on overflow. See also: inc'".to_string() },
        CoreSymbol { name: "inc'".to_string(), params: "([x])".to_string(), doc: "Returns a number one greater than num. Supports arbitrary precision.\n  See also: inc".to_string() },
        CoreSymbol { name: "indexed?".to_string(), params: "([coll])".to_string(), doc: "Return true if coll implements Indexed, indicating efficient lookup by index".to_string() },
        CoreSymbol { name: "infinite?".to_string(), params: "([num])".to_string(), doc: "Returns true if num is negative or positive infinity, else false".to_string() },
        CoreSymbol { name: "inst-ms".to_string(), params: "([inst])".to_string(), doc: "Return the number of milliseconds since January 1, 1970, 00:00:00 GMT".to_string() },
        CoreSymbol { name: "inst?".to_string(), params: "([x])".to_string(), doc: "Return true if x satisfies Inst".to_string() },
        CoreSymbol { name: "instance?".to_string(), params: "([c x])".to_string(), doc: "Evaluates x and tests if it is an instance of the class\n    c. Returns true or false".to_string() },
        CoreSymbol { name: "int".to_string(), params: "([x])".to_string(), doc: "Coerce to int".to_string() },
        CoreSymbol { name: "int-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of ints".to_string() },
        CoreSymbol { name: "int?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a fixed precision integer".to_string() },
        CoreSymbol { name: "integer?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is an integer".to_string() },
        CoreSymbol { name: "interleave".to_string(), params: "([] [c1] [c1 c2] [c1 c2 & colls])".to_string(), doc: "Returns a lazy seq of the first item in each coll, then the second etc.".to_string() },
        CoreSymbol { name: "intern".to_string(), params: "([ns name] [ns name val])".to_string(), doc: "Finds or creates a var named by the symbol name in the namespace\n  ns (which can be a symbol or a namespace), setting its root binding\n  to val if supplied. The namespace must exist. The var will adopt any\n  metadata from the name symbol.  Returns the var.".to_string() },
        CoreSymbol { name: "interpose".to_string(), params: "([sep] [sep coll])".to_string(), doc: "Returns a lazy seq of the elements of coll separated by sep.\n  Returns a stateful transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "into".to_string(), params: "([] [to] [to from] [to xform from])".to_string(), doc: "Returns a new coll consisting of to-coll with all of the items of\n  from-coll conjoined. A transducer may be supplied.".to_string() },
        CoreSymbol { name: "into-array".to_string(), params: "([aseq] [type aseq])".to_string(), doc: "Returns an array with components set to the values in aseq. The array's\n  component type is type if provided, or the type of the first value in\n  aseq if present, or Object. All values in aseq must be compatible with\n  the component type. Class objects for the primitive types can be obtained\n  using, e.g., Integer/TYPE.".to_string() },
        CoreSymbol { name: "ints".to_string(), params: "([xs])".to_string(), doc: "Casts to int[]".to_string() },
        CoreSymbol { name: "isa?".to_string(), params: "([child parent] [h child parent])".to_string(), doc: "Returns true if (= child parent), or child is directly or indirectly derived from\n  parent, either via a Java type inheritance relationship or a\n  relationship established via derive. h must be a hierarchy obtained\n  from make-hierarchy, if not supplied defaults to the global\n  hierarchy".to_string() },
        CoreSymbol { name: "iterate".to_string(), params: "([f x])".to_string(), doc: "Returns a lazy sequence of x, (f x), (f (f x)) etc. f must be free of side-effects".to_string() },
        CoreSymbol { name: "iteration".to_string(), params: "([step & {:keys [somef vf kf initk], :or {vf identity, kf identity, somef some?, initk nil}}])".to_string(), doc: "Creates a seqable/reducible via repeated calls to step,\n  a function of some (continuation token) 'k'. The first call to step\n  will be passed initk, returning 'ret'. Iff (somef ret) is true,\n  (vf ret) will be included in the iteration, else iteration will\n  terminate and vf/kf will not be called. If (kf ret) is non-nil it\n  will be passed to the next step call, else iteration will terminate.\n\n  This can be used e.g. to consume APIs that return paginated or batched data.\n\n   step - (possibly impure) fn of 'k' -> 'ret'\n\n   :somef - fn of 'ret' -> logical true/false, default 'some?'\n   :vf - fn of 'ret' -> 'v', a value produced by the iteration, default 'identity'\n   :kf - fn of 'ret' -> 'next-k' or nil (signaling 'do not continue'), default 'identity'\n   :initk - the first value passed to step, default 'nil'\n\n  It is presumed that step with non-initk is unreproducible/non-idempotent.\n  If step with initk is unreproducible it is on the consumer to not consume twice.".to_string() },
        CoreSymbol { name: "iterator-seq".to_string(), params: "([iter])".to_string(), doc: "Returns a seq on a java.util.Iterator. Note that most collections\n  providing iterators implement Iterable and thus support seq directly.\n  Seqs cache values, thus iterator-seq should not be used on any\n  iterator that repeatedly returns the same mutable object.".to_string() },
        CoreSymbol { name: "juxt".to_string(), params: "([f] [f g] [f g h] [f g h & fs])".to_string(), doc: "Takes a set of functions and returns a fn that is the juxtaposition\n  of those fns.  The returned fn takes a variable number of args, and\n  returns a vector containing the result of applying each fn to the\n  args (left-to-right).\n  ((juxt a b c) x) => [(a x) (b x) (c x)]".to_string() },
        CoreSymbol { name: "keep".to_string(), params: "([f] [f coll])".to_string(), doc: "Returns a lazy sequence of the non-nil results of (f item). Note,\n  this means false return values will be included.  f must be free of\n  side-effects.  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "keep-indexed".to_string(), params: "([f] [f coll])".to_string(), doc: "Returns a lazy sequence of the non-nil results of (f index item). Note,\n  this means false return values will be included.  f must be free of\n  side-effects.  Returns a stateful transducer when no collection is\n  provided.".to_string() },
        CoreSymbol { name: "key".to_string(), params: "([e])".to_string(), doc: "Returns the key of the map entry.".to_string() },
        CoreSymbol { name: "keys".to_string(), params: "([map])".to_string(), doc: "Returns a sequence of the map's keys, in the same order as (seq map).".to_string() },
        CoreSymbol { name: "keyword".to_string(), params: "([name] [ns name])".to_string(), doc: "Returns a Keyword with the given namespace and name.  Do not use :\n  in the keyword strings, it will be added automatically.".to_string() },
        CoreSymbol { name: "keyword?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a Keyword".to_string() },
        CoreSymbol { name: "last".to_string(), params: "([coll])".to_string(), doc: "Return the last item in coll, in linear time".to_string() },
        CoreSymbol { name: "lazy-cat".to_string(), params: "([& colls])".to_string(), doc: "Expands to code which yields a lazy sequence of the concatenation\n  of the supplied colls.  Each coll expr is not evaluated until it is\n  needed. \n\n  (lazy-cat xs ys zs) === (concat (lazy-seq xs) (lazy-seq ys) (lazy-seq zs))".to_string() },
        CoreSymbol { name: "lazy-seq".to_string(), params: "([& body])".to_string(), doc: "Takes a body of expressions that returns an ISeq or nil, and yields\n  a Seqable object that will invoke the body only the first time seq\n  is called, and will cache the result and return it on all subsequent\n  seq calls. See also - realized?".to_string() },
        CoreSymbol { name: "let".to_string(), params: "([bindings & body])".to_string(), doc: "binding => binding-form init-expr\n  binding-form => name, or destructuring-form\n  destructuring-form => map-destructure-form, or seq-destructure-form\n\n  Evaluates the exprs in a lexical context in which the symbols in\n  the binding-forms are bound to their respective init-exprs or parts\n  therein.\n\n  See https://clojure.org/reference/special_forms#binding-forms for\n  more information about destructuring.".to_string() },
        CoreSymbol { name: "letfn".to_string(), params: "([fnspecs & body])".to_string(), doc: "fnspec ==> (fname [params*] exprs) or (fname ([params*] exprs)+)\n\n  Takes a vector of function specs and a body, and generates a set of\n  bindings of functions to their names. All of the names are available\n  in all of the definitions of the functions, as well as the body.".to_string() },
        CoreSymbol { name: "line-seq".to_string(), params: "([rdr])".to_string(), doc: "Returns the lines of text from rdr as a lazy sequence of strings.\n  rdr must implement java.io.BufferedReader.".to_string() },
        CoreSymbol { name: "list".to_string(), params: "([& items])".to_string(), doc: "Creates a new list containing the items.".to_string() },
        CoreSymbol { name: "list*".to_string(), params: "([args] [a args] [a b args] [a b c args] [a b c d & more])".to_string(), doc: "Creates a new seq containing the items prepended to the rest, the\n  last of which will be treated as a sequence.".to_string() },
        CoreSymbol { name: "list?".to_string(), params: "([x])".to_string(), doc: "Returns true if x implements IPersistentList".to_string() },
        CoreSymbol { name: "load-file".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "load-string".to_string(), params: "([s])".to_string(), doc: "Sequentially read and evaluate the set of forms contained in the\n  string".to_string() },
        CoreSymbol { name: "loaded-libs".to_string(), params: "([])".to_string(), doc: "Returns a sorted set of symbols naming the currently loaded libs".to_string() },
        CoreSymbol { name: "locking".to_string(), params: "([x & body])".to_string(), doc: "Executes exprs in an implicit do, while holding the monitor of x.\n  Will release the monitor of x in all circumstances.".to_string() },
        CoreSymbol { name: "long".to_string(), params: "([x])".to_string(), doc: "Coerce to long".to_string() },
        CoreSymbol { name: "long-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of longs".to_string() },
        CoreSymbol { name: "longs".to_string(), params: "([xs])".to_string(), doc: "Casts to long[]".to_string() },
        CoreSymbol { name: "loop".to_string(), params: "([bindings & body])".to_string(), doc: "Evaluates the exprs in a lexical context in which the symbols in\n  the binding-forms are bound to their respective init-exprs or parts\n  therein. Acts as a recur target.".to_string() },
        CoreSymbol { name: "macroexpand".to_string(), params: "([form])".to_string(), doc: "Repeatedly calls macroexpand-1 on form until it no longer\n  represents a macro form, then returns it.  Note neither\n  macroexpand-1 nor macroexpand expand macros in subforms.".to_string() },
        CoreSymbol { name: "macroexpand-1".to_string(), params: "([form])".to_string(), doc: "If form represents a macro form, returns its expansion,\n  else returns form.".to_string() },
        CoreSymbol { name: "make-array".to_string(), params: "([type len] [type dim & more-dims])".to_string(), doc: "Creates and returns an array of instances of the specified class of\n  the specified dimension(s).  Note that a class object is required.\n  Class objects can be obtained by using their imported or\n  fully-qualified name.  Class objects for the primitive types can be\n  obtained using, e.g., Integer/TYPE.".to_string() },
        CoreSymbol { name: "make-hierarchy".to_string(), params: "([])".to_string(), doc: "Creates a hierarchy object for use with derive, isa? etc.".to_string() },
        CoreSymbol { name: "map".to_string(), params: "([f] [f coll] [f c1 c2] [f c1 c2 c3] [f c1 c2 c3 & colls])".to_string(), doc: "Returns a lazy sequence consisting of the result of applying f to\n  the set of first items of each coll, followed by applying f to the\n  set of second items in each coll, until any one of the colls is\n  exhausted.  Any remaining items in other colls are ignored. Function\n  f should accept number-of-colls arguments. Returns a transducer when\n  no collection is provided.".to_string() },
        CoreSymbol { name: "map-entry?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a map entry".to_string() },
        CoreSymbol { name: "map-indexed".to_string(), params: "([f] [f coll])".to_string(), doc: "Returns a lazy sequence consisting of the result of applying f to 0\n  and the first item of coll, followed by applying f to 1 and the second\n  item in coll, etc, until coll is exhausted. Thus function f should\n  accept 2 arguments, index and item. Returns a stateful transducer when\n  no collection is provided.".to_string() },
        CoreSymbol { name: "map?".to_string(), params: "([x])".to_string(), doc: "Return true if x implements IPersistentMap".to_string() },
        CoreSymbol { name: "mapcat".to_string(), params: "([f] [f & colls])".to_string(), doc: "Returns the result of applying concat to the result of applying map\n  to f and colls.  Thus function f should return a collection. Returns\n  a transducer when no collections are provided".to_string() },
        CoreSymbol { name: "mapv".to_string(), params: "([f coll] [f c1 c2] [f c1 c2 c3] [f c1 c2 c3 & colls])".to_string(), doc: "Returns a vector consisting of the result of applying f to the\n  set of first items of each coll, followed by applying f to the set\n  of second items in each coll, until any one of the colls is\n  exhausted.  Any remaining items in other colls are ignored. Function\n  f should accept number-of-colls arguments.".to_string() },
        CoreSymbol { name: "max".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns the greatest of the nums.".to_string() },
        CoreSymbol { name: "max-key".to_string(), params: "([k x] [k x y] [k x y & more])".to_string(), doc: "Returns the x for which (k x), a number, is greatest.\n\n  If there are multiple such xs, the last one is returned.".to_string() },
        CoreSymbol { name: "memfn".to_string(), params: "([name & args])".to_string(), doc: "Expands into code that creates a fn that expects to be passed an\n  object and any args and calls the named instance method on the\n  object passing the args. Use when you want to treat a Java method as\n  a first-class fn. name may be type-hinted with the method receiver's\n  type in order to avoid reflective calls.".to_string() },
        CoreSymbol { name: "memoize".to_string(), params: "([f])".to_string(), doc: "Returns a memoized version of a referentially transparent function. The\n  memoized version of the function keeps a cache of the mapping from arguments\n  to results and, when calls with the same arguments are repeated often, has\n  higher performance at the expense of higher memory use.".to_string() },
        CoreSymbol { name: "merge".to_string(), params: "([& maps])".to_string(), doc: "Returns a map that consists of the rest of the maps conj-ed onto\n  the first.  If a key occurs in more than one map, the mapping from\n  the latter (left-to-right) will be the mapping in the result.".to_string() },
        CoreSymbol { name: "merge-with".to_string(), params: "([f & maps])".to_string(), doc: "Returns a map that consists of the rest of the maps conj-ed onto\n  the first.  If a key occurs in more than one map, the mapping(s)\n  from the latter (left-to-right) will be combined with the mapping in\n  the result by calling (f val-in-result val-in-latter).".to_string() },
        CoreSymbol { name: "meta".to_string(), params: "([obj])".to_string(), doc: "Returns the metadata of obj, returns nil if there is no metadata.".to_string() },
        CoreSymbol { name: "methods".to_string(), params: "([multifn])".to_string(), doc: "Given a multimethod, returns a map of dispatch values -> dispatch fns".to_string() },
        CoreSymbol { name: "min".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Returns the least of the nums.".to_string() },
        CoreSymbol { name: "min-key".to_string(), params: "([k x] [k x y] [k x y & more])".to_string(), doc: "Returns the x for which (k x), a number, is least.\n\n  If there are multiple such xs, the last one is returned.".to_string() },
        CoreSymbol { name: "mod".to_string(), params: "([num div])".to_string(), doc: "Modulus of num and div. Truncates toward negative infinity.".to_string() },
        CoreSymbol { name: "multi-fn-add-method-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "multi-fn-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "multi-fn?-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "munge".to_string(), params: "([s])".to_string(), doc: "".to_string() },
        CoreSymbol { name: "name".to_string(), params: "([x])".to_string(), doc: "Returns the name String of a string, symbol or keyword.".to_string() },
        CoreSymbol { name: "namespace".to_string(), params: "([x])".to_string(), doc: "Returns the namespace String of a symbol or keyword, or nil if not present.".to_string() },
        CoreSymbol { name: "namespace-munge".to_string(), params: "([ns])".to_string(), doc: "Convert a Clojure namespace name to a legal Java package name.".to_string() },
        CoreSymbol { name: "nat-int?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a non-negative fixed precision integer".to_string() },
        CoreSymbol { name: "neg-int?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a negative fixed precision integer".to_string() },
        CoreSymbol { name: "neg?".to_string(), params: "([num])".to_string(), doc: "Returns true if num is less than zero, else false".to_string() },
        CoreSymbol { name: "newline".to_string(), params: "([])".to_string(), doc: "Writes a platform-specific newline to *out*".to_string() },
        CoreSymbol { name: "next".to_string(), params: "([coll])".to_string(), doc: "Returns a seq of the items after the first. Calls seq on its\n  argument.  If there are no more items, returns nil.".to_string() },
        CoreSymbol { name: "nfirst".to_string(), params: "([x])".to_string(), doc: "Same as (next (first x))".to_string() },
        CoreSymbol { name: "nil?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is nil, false otherwise.".to_string() },
        CoreSymbol { name: "nnext".to_string(), params: "([x])".to_string(), doc: "Same as (next (next x))".to_string() },
        CoreSymbol { name: "not".to_string(), params: "([x])".to_string(), doc: "Returns true if x is logical false, false otherwise.".to_string() },
        CoreSymbol { name: "not-any?".to_string(), params: "([pred coll])".to_string(), doc: "Returns false if (pred x) is logical true for any x in coll,\n  else true.".to_string() },
        CoreSymbol { name: "not-empty".to_string(), params: "([coll])".to_string(), doc: "If coll is empty, returns nil, else coll".to_string() },
        CoreSymbol { name: "not-every?".to_string(), params: "([pred coll])".to_string(), doc: "Returns false if (pred x) is logical true for every x in\n  coll, else true.".to_string() },
        CoreSymbol { name: "not=".to_string(), params: "([x] [x y] [x y & more])".to_string(), doc: "Same as (not (= obj1 obj2))".to_string() },
        CoreSymbol { name: "ns".to_string(), params: "([name docstring? attr-map? references*])".to_string(), doc: "Sets *ns* to the namespace named by name (unevaluated), creating it\n  if needed.  references can be zero or more of: (:refer-clojure ...)\n  (:require ...) (:use ...) (:import ...) (:load ...) (:gen-class)\n  with the syntax of refer-clojure/require/use/import/load/gen-class\n  respectively, except the arguments are unevaluated and need not be\n  quoted. (:gen-class ...), when supplied, defaults to :name\n  corresponding to the ns name, :main true, :impl-ns same as ns, and\n  :init-impl-ns true. All options of gen-class are\n  supported. The :gen-class directive is ignored when not\n  compiling. If :gen-class is not supplied, when compiled only an\n  nsname__init.class will be generated. If :refer-clojure is not used, a\n  default (refer 'clojure.core) is used.  Use of ns is preferred to\n  individual calls to in-ns/require/use/import:\n\n  (ns foo.bar\n    (:refer-clojure :exclude [ancestors printf])\n    (:require (clojure.contrib sql combinatorics))\n    (:use (my.lib this that))\n    (:import (java.util Date Timer Random)\n             (java.sql Connection Statement)))".to_string() },
        CoreSymbol { name: "ns-aliases".to_string(), params: "([ns])".to_string(), doc: "Returns a map of the aliases for the namespace.".to_string() },
        CoreSymbol { name: "ns-imports".to_string(), params: "([ns])".to_string(), doc: "Returns a map of the import mappings for the namespace.".to_string() },
        CoreSymbol { name: "ns-interns".to_string(), params: "([ns])".to_string(), doc: "Returns a map of the intern mappings for the namespace.".to_string() },
        CoreSymbol { name: "ns-map".to_string(), params: "([ns])".to_string(), doc: "Returns a map of all the mappings for the namespace.".to_string() },
        CoreSymbol { name: "ns-name".to_string(), params: "([ns])".to_string(), doc: "Returns the name of the namespace, a symbol.".to_string() },
        CoreSymbol { name: "ns-publics".to_string(), params: "([ns])".to_string(), doc: "Returns a map of the public intern mappings for the namespace.".to_string() },
        CoreSymbol { name: "ns-refers".to_string(), params: "([ns])".to_string(), doc: "Returns a map of the refer mappings for the namespace.".to_string() },
        CoreSymbol { name: "ns-resolve".to_string(), params: "([ns sym] [ns env sym])".to_string(), doc: "Returns the var or Class to which a symbol will be resolved in the\n  namespace (unless found in the environment), else nil.  Note that\n  if the symbol is fully qualified, the var/Class to which it resolves\n  need not be present in the namespace.".to_string() },
        CoreSymbol { name: "ns-unalias".to_string(), params: "([ns sym])".to_string(), doc: "Removes the alias for the symbol from the namespace.".to_string() },
        CoreSymbol { name: "ns-unmap".to_string(), params: "([ns sym])".to_string(), doc: "Removes the mappings for the symbol from the namespace.".to_string() },
        CoreSymbol { name: "nth".to_string(), params: "([coll index] [coll index not-found])".to_string(), doc: "Returns the value at the index. get returns nil if index out of\n  bounds, nth throws an exception unless not-found is supplied.  nth\n  also works for strings, Java arrays, regex Matchers and Lists, and,\n  in O(n) time, for sequences.".to_string() },
        CoreSymbol { name: "nthnext".to_string(), params: "([coll n])".to_string(), doc: "Returns the nth next of coll, (seq coll) when n is 0.".to_string() },
        CoreSymbol { name: "nthrest".to_string(), params: "([coll n])".to_string(), doc: "Returns the nth rest of coll, coll when n is 0.".to_string() },
        CoreSymbol { name: "num".to_string(), params: "([x])".to_string(), doc: "Coerce to Number".to_string() },
        CoreSymbol { name: "number?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is a Number".to_string() },
        CoreSymbol { name: "numerator".to_string(), params: "([r])".to_string(), doc: "Returns the numerator part of a Ratio.".to_string() },
        CoreSymbol { name: "object-array".to_string(), params: "([size-or-seq])".to_string(), doc: "Creates an array of objects".to_string() },
        CoreSymbol { name: "odd?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is odd, throws an exception if n is not an integer".to_string() },
        CoreSymbol { name: "or".to_string(), params: "([] [x] [x & next])".to_string(), doc: "Evaluates exprs one at a time, from left to right. If a form\n  returns a logical true value, or returns that value and doesn't\n  evaluate any of the other expressions, otherwise it returns the\n  value of the last expression. (or) returns nil.".to_string() },
        CoreSymbol { name: "parents".to_string(), params: "([tag] [h tag])".to_string(), doc: "Returns the immediate parents of tag, either via a Java type\n  inheritance relationship or a relationship established via derive. h\n  must be a hierarchy obtained from make-hierarchy, if not supplied\n  defaults to the global hierarchy".to_string() },
        CoreSymbol { name: "parse-boolean".to_string(), params: "([s])".to_string(), doc: "Parse strings \"true\" or \"false\" and return a boolean, or nil if invalid".to_string() },
        CoreSymbol { name: "parse-double".to_string(), params: "([s])".to_string(), doc: "Parse string with floating point components and return a Double value,\n  or nil if parse fails.\n\n  Grammar: https://docs.oracle.com/javase/8/docs/api/java/lang/Double.html#valueOf-java.lang.String-".to_string() },
        CoreSymbol { name: "parse-long".to_string(), params: "([s])".to_string(), doc: "Parse string of decimal digits with optional leading -/+ and return a\n  Long value, or nil if parse fails".to_string() },
        CoreSymbol { name: "parse-uuid".to_string(), params: "([s])".to_string(), doc: "Parse a string representing a UUID and return a java.util.UUID instance,\n  or nil if parse fails.\n\n  Grammar: https://docs.oracle.com/javase/8/docs/api/java/util/UUID.html#toString--".to_string() },
        CoreSymbol { name: "partial".to_string(), params: "([f] [f arg1] [f arg1 arg2] [f arg1 arg2 arg3] [f arg1 arg2 arg3 & more])".to_string(), doc: "Takes a function f and fewer than the normal arguments to f, and\n  returns a fn that takes a variable number of additional args. When\n  called, the returned function calls f with args + additional args.".to_string() },
        CoreSymbol { name: "partition".to_string(), params: "([n coll] [n step coll] [n step pad coll])".to_string(), doc: "Returns a lazy sequence of lists of n items each, at offsets step\n  apart. If step is not supplied, defaults to n, i.e. the partitions\n  do not overlap. If a pad collection is supplied, use its elements as\n  necessary to complete last partition upto n items. In case there are\n  not enough padding elements, return a partition with less than n items.".to_string() },
        CoreSymbol { name: "partition-all".to_string(), params: "([n] [n coll] [n step coll])".to_string(), doc: "Returns a lazy sequence of lists like partition, but may include\n  partitions with fewer than n items at the end.  Returns a stateful\n  transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "partition-by".to_string(), params: "([f] [f coll])".to_string(), doc: "Applies f to each value in coll, splitting it each time f returns a\n   new value.  Returns a lazy seq of partitions.  Returns a stateful\n   transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "peek".to_string(), params: "([coll])".to_string(), doc: "For a list or queue, same as first, for a vector, same as, but much\n  more efficient than, last. If the collection is empty, returns nil.".to_string() },
        CoreSymbol { name: "persistent!".to_string(), params: "([coll])".to_string(), doc: "Returns a new, persistent version of the transient collection, in\n  constant time. The transient collection cannot be used after this\n  call, any such use will throw an exception.".to_string() },
        CoreSymbol { name: "pmap".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "pop".to_string(), params: "([coll])".to_string(), doc: "For a list or queue, returns a new list/queue without the first\n  item, for a vector, returns a new vector without the last item. If\n  the collection is empty, throws an exception.  Note - not the same\n  as next/butlast.".to_string() },
        CoreSymbol { name: "pop!".to_string(), params: "([coll])".to_string(), doc: "Removes the last item from a transient vector. If\n  the collection is empty, throws an exception. Returns coll".to_string() },
        CoreSymbol { name: "pop-thread-bindings".to_string(), params: "([])".to_string(), doc: "Pop one set of bindings pushed with push-binding before. It is an error to\n  pop bindings without pushing before.".to_string() },
        CoreSymbol { name: "pos-int?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a positive fixed precision integer".to_string() },
        CoreSymbol { name: "pos?".to_string(), params: "([num])".to_string(), doc: "Returns true if num is greater than zero, else false".to_string() },
        CoreSymbol { name: "pr".to_string(), params: "([] [x] [x & more])".to_string(), doc: "Prints the object(s) to the output stream that is the current value\n  of *out*.  Prints the object(s), separated by spaces if there is\n  more than one.  By default, pr and prn print in a way that objects\n  can be read by the reader".to_string() },
        CoreSymbol { name: "pr-str".to_string(), params: "([& xs])".to_string(), doc: "pr to a string, returning it".to_string() },
        CoreSymbol { name: "prefer-method".to_string(), params: "([multifn dispatch-val-x dispatch-val-y])".to_string(), doc: "Causes the multimethod to prefer matches of dispatch-val-x over dispatch-val-y \n   when there is a conflict".to_string() },
        CoreSymbol { name: "prefers".to_string(), params: "([multifn])".to_string(), doc: "Given a multimethod, returns a map of preferred value -> set of other values".to_string() },
        CoreSymbol { name: "print".to_string(), params: "([& more])".to_string(), doc: "Prints the object(s) to the output stream that is the current value\n  of *out*.  print and println produce output for human consumption.".to_string() },
        CoreSymbol { name: "print-dup".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "print-method".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "print-str".to_string(), params: "([& xs])".to_string(), doc: "print to a string, returning it".to_string() },
        CoreSymbol { name: "printf".to_string(), params: "([fmt & args])".to_string(), doc: "Prints formatted output, as per format".to_string() },
        CoreSymbol { name: "println".to_string(), params: "([& more])".to_string(), doc: "Same as print followed by (newline)".to_string() },
        CoreSymbol { name: "prn".to_string(), params: "([& more])".to_string(), doc: "Same as pr followed by (newline). Observes *flush-on-newline*".to_string() },
        CoreSymbol { name: "prn-str".to_string(), params: "([& xs])".to_string(), doc: "prn to a string, returning it".to_string() },
        CoreSymbol { name: "promise".to_string(), params: "([])".to_string(), doc: "Returns a promise object that can be read with deref/@, and set,\n  once only, with deliver. Calls to deref/@ prior to delivery will\n  block, unless the variant of deref with timeout is used. All\n  subsequent derefs will return the same delivered value without\n  blocking. See also - realized?.".to_string() },
        CoreSymbol { name: "protocol-type-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "proxy".to_string(), params: "([class-and-interfaces args & fs])".to_string(), doc: "class-and-interfaces - a vector of class names\n\n  args - a (possibly empty) vector of arguments to the superclass\n  constructor.\n\n  f => (name [params*] body) or\n  (name ([params*] body) ([params+] body) ...)\n\n  Expands to code which creates a instance of a proxy class that\n  implements the named class/interface(s) by calling the supplied\n  fns. A single class, if provided, must be first. If not provided it\n  defaults to Object.\n\n  The interfaces names must be valid interface types. If a method fn\n  is not provided for a class method, the superclass method will be\n  called. If a method fn is not provided for an interface method, an\n  UnsupportedOperationException will be thrown should it be\n  called. Method fns are closures and can capture the environment in\n  which proxy is called. Each method fn takes an additional implicit\n  first arg, which is bound to 'this. Note that while method fns can\n  be provided to override protected methods, they have no other access\n  to protected members, nor to super, as these capabilities cannot be\n  proxied.".to_string() },
        CoreSymbol { name: "proxy*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "push-thread-bindings".to_string(), params: "([bindings])".to_string(), doc: "WARNING: This is a low-level function. Prefer high-level macros like\n  binding where ever possible.\n\n  Takes a map of Var/value pairs. Binds each Var to the associated value for\n  the current thread. Each call *MUST* be accompanied by a matching call to\n  pop-thread-bindings wrapped in a try-finally!\n  \n      (push-thread-bindings bindings)\n      (try\n        ...\n        (finally\n          (pop-thread-bindings)))".to_string() },
        CoreSymbol { name: "qualified-ident?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a symbol or keyword with a namespace".to_string() },
        CoreSymbol { name: "qualified-keyword?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a keyword with a namespace".to_string() },
        CoreSymbol { name: "qualified-symbol?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a symbol with a namespace".to_string() },
        CoreSymbol { name: "quot".to_string(), params: "([num div])".to_string(), doc: "quot[ient] of dividing numerator by denominator.".to_string() },
        CoreSymbol { name: "rand".to_string(), params: "([] [n])".to_string(), doc: "Returns a random floating point number between 0 (inclusive) and\n  n (default 1) (exclusive).".to_string() },
        CoreSymbol { name: "rand-int".to_string(), params: "([n])".to_string(), doc: "Returns a random integer between 0 (inclusive) and n (exclusive).".to_string() },
        CoreSymbol { name: "rand-nth".to_string(), params: "([coll])".to_string(), doc: "Return a random element of the (sequential) collection. Will have\n  the same performance characteristics as nth for the given\n  collection.".to_string() },
        CoreSymbol { name: "random-sample".to_string(), params: "([prob] [prob coll])".to_string(), doc: "Returns items from coll with random probability of prob (0.0 -\n  1.0).  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "random-uuid".to_string(), params: "([])".to_string(), doc: "Returns a pseudo-randomly generated java.util.UUID instance (i.e. type 4).\n\n  See: https://docs.oracle.com/javase/8/docs/api/java/util/UUID.html#randomUUID--".to_string() },
        CoreSymbol { name: "range".to_string(), params: "([] [end] [start end] [start end step])".to_string(), doc: "Returns a lazy seq of nums from start (inclusive) to end\n  (exclusive), by step, where start defaults to 0, step to 1, and end to\n  infinity. When step is equal to 0, returns an infinite sequence of\n  start. When start is equal to end, returns empty list.".to_string() },
        CoreSymbol { name: "ratio?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is a Ratio".to_string() },
        CoreSymbol { name: "rational?".to_string(), params: "([n])".to_string(), doc: "Returns true if n is a rational number".to_string() },
        CoreSymbol { name: "rationalize".to_string(), params: "([num])".to_string(), doc: "returns the rational value of num".to_string() },
        CoreSymbol { name: "re-find".to_string(), params: "([m] [re s])".to_string(), doc: "Returns the next regex match, if any, of string to pattern, using\n  java.util.regex.Matcher.find().  Uses re-groups to return the\n  groups.".to_string() },
        CoreSymbol { name: "re-groups".to_string(), params: "([m])".to_string(), doc: "Returns the groups from the most recent match/find. If there are no\n  nested groups, returns a string of the entire match. If there are\n  nested groups, returns a vector of the groups, the first element\n  being the entire match.".to_string() },
        CoreSymbol { name: "re-matcher".to_string(), params: "([re s])".to_string(), doc: "Returns an instance of java.util.regex.Matcher, for use, e.g. in\n  re-find.".to_string() },
        CoreSymbol { name: "re-matches".to_string(), params: "([re s])".to_string(), doc: "Returns the match, if any, of string to pattern, using\n  java.util.regex.Matcher.matches().  Uses re-groups to return the\n  groups.".to_string() },
        CoreSymbol { name: "re-pattern".to_string(), params: "([s])".to_string(), doc: "Returns an instance of java.util.regex.Pattern, for use, e.g. in\n  re-matcher.".to_string() },
        CoreSymbol { name: "re-seq".to_string(), params: "([re s])".to_string(), doc: "Returns a lazy sequence of successive matches of pattern in string,\n  using java.util.regex.Matcher.find(), each such match processed with\n  re-groups.".to_string() },
        CoreSymbol { name: "read".to_string(), params: "([] [stream] [stream eof-error? eof-value] [stream eof-error? eof-value recursive?] [opts stream])".to_string(), doc: "Reads the next object from stream, which must be an instance of\n  java.io.PushbackReader or some derivee.  stream defaults to the\n  current value of *in*.\n\n  Opts is a persistent map with valid keys:\n    :read-cond - :allow to process reader conditionals, or\n                 :preserve to keep all branches\n    :features - persistent set of feature keywords for reader conditionals\n    :eof - on eof, return value unless :eofthrow, then throw.\n           if not specified, will throw\n\n  Note that read can execute code (controlled by *read-eval*),\n  and as such should be used only with trusted sources.\n\n  For data structure interop use clojure.edn/read".to_string() },
        CoreSymbol { name: "read+string".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "read-line".to_string(), params: "([])".to_string(), doc: "Reads the next line from stream that is the current value of *in* .".to_string() },
        CoreSymbol { name: "read-string".to_string(), params: "([s] [opts s])".to_string(), doc: "Reads one object from the string s. Optionally include reader\n  options, as specified in read.\n\n  Note that read-string can execute code (controlled by *read-eval*),\n  and as such should be used only with trusted sources.\n\n  For data structure interop use clojure.edn/read-string".to_string() },
        CoreSymbol { name: "reader-conditional".to_string(), params: "([form splicing?])".to_string(), doc: "Construct a data representation of a reader conditional.\n  If true, splicing? indicates read-cond-splicing.".to_string() },
        CoreSymbol { name: "reader-conditional?".to_string(), params: "([value])".to_string(), doc: "Return true if the value is the data representation of a reader conditional".to_string() },
        CoreSymbol { name: "realized?".to_string(), params: "([x])".to_string(), doc: "Returns true if a value has been produced for a promise, delay, future or lazy sequence.".to_string() },
        CoreSymbol { name: "record?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is a record".to_string() },
        CoreSymbol { name: "reduce".to_string(), params: "([f coll] [f val coll])".to_string(), doc: "f should be a function of 2 arguments. If val is not supplied,\n  returns the result of applying f to the first 2 items in coll, then\n  applying f to that result and the 3rd item, etc. If coll contains no\n  items, f must accept no arguments as well, and reduce returns the\n  result of calling f with no arguments.  If coll has only 1 item, it\n  is returned and f is not called.  If val is supplied, returns the\n  result of applying f to val and the first item in coll, then\n  applying f to that result and the 2nd item, etc. If coll contains no\n  items, returns val and f is not called.".to_string() },
        CoreSymbol { name: "reduce-kv".to_string(), params: "([f init coll])".to_string(), doc: "Reduces an associative collection. f should be a function of 3\n  arguments. Returns the result of applying f to init, the first key\n  and the first value in coll, then applying f to that result and the\n  2nd key and value, etc. If coll contains no entries, returns init\n  and f is not called. Note that reduce-kv is supported on vectors,\n  where the keys will be the ordinals.".to_string() },
        CoreSymbol { name: "reduced".to_string(), params: "([x])".to_string(), doc: "Wraps x in a way such that a reduce will terminate with the value x".to_string() },
        CoreSymbol { name: "reduced?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is the result of a call to reduced".to_string() },
        CoreSymbol { name: "reductions".to_string(), params: "([f coll] [f init coll])".to_string(), doc: "Returns a lazy seq of the intermediate values of the reduction (as\n  per reduce) of coll by f, starting with init.".to_string() },
        CoreSymbol { name: "ref".to_string(), params: "([x] [x & options])".to_string(), doc: "Creates and returns a Ref with an initial value of x and zero or\n  more options (in any order):\n\n  :meta metadata-map\n\n  :validator validate-fn\n\n  :min-history (default 0)\n  :max-history (default 10)\n\n  If metadata-map is supplied, it will become the metadata on the\n  ref. validate-fn must be nil or a side-effect-free fn of one\n  argument, which will be passed the intended new state on any state\n  change. If the new state is unacceptable, the validate-fn should\n  return false or throw an exception. validate-fn will be called on\n  transaction commit, when all refs have their final values.\n\n  Normally refs accumulate history dynamically as needed to deal with\n  read demands. If you know in advance you will need history you can\n  set :min-history to ensure it will be available when first needed (instead\n  of after a read fault). History is limited, and the limit can be set\n  with :max-history.".to_string() },
        CoreSymbol { name: "ref-set".to_string(), params: "([ref val])".to_string(), doc: "Must be called in a transaction. Sets the value of ref.\n  Returns val.".to_string() },
        CoreSymbol { name: "refer".to_string(), params: "([ns-sym & filters])".to_string(), doc: "refers to all public vars of ns, subject to filters.\n  filters can include at most one each of:\n\n  :exclude list-of-symbols\n  :only list-of-symbols\n  :rename map-of-fromsymbol-tosymbol\n\n  For each public interned var in the namespace named by the symbol,\n  adds a mapping from the name of the var to the var to the current\n  namespace.  Throws an exception if name is already mapped to\n  something else in the current namespace. Filters can be used to\n  select a subset, via inclusion or exclusion, or to provide a mapping\n  to a symbol different from the var's name, in order to prevent\n  clashes. Use :use in the ns macro in preference to calling this directly.".to_string() },
        CoreSymbol { name: "refer-clojure".to_string(), params: "([& filters])".to_string(), doc: "Same as (refer 'clojure.core <filters>)".to_string() },
        CoreSymbol { name: "reify".to_string(), params: "([& opts+specs])".to_string(), doc: "reify creates an object implementing a protocol or interface.\n  reify is a macro with the following structure:\n\n (reify options* specs*)\n  \n  Currently there are no options.\n\n  Each spec consists of the protocol or interface name followed by zero\n  or more method bodies:\n\n  protocol-or-interface-or-Object\n  (methodName [args+] body)*\n\n  Methods should be supplied for all methods of the desired\n  protocol(s) and interface(s). You can also define overrides for\n  methods of Object. Note that the first parameter must be supplied to\n  correspond to the target object ('this' in Java parlance). Thus\n  methods for interfaces will take one more argument than do the\n  interface declarations.  Note also that recur calls to the method\n  head should *not* pass the target object, it will be supplied\n  automatically and can not be substituted.\n\n  The return type can be indicated by a type hint on the method name,\n  and arg types can be indicated by a type hint on arg names. If you\n  leave out all hints, reify will try to match on same name/arity\n  method in the protocol(s)/interface(s) - this is preferred. If you\n  supply any hints at all, no inference is done, so all hints (or\n  default of Object) must be correct, for both arguments and return\n  type. If a method is overloaded in a protocol/interface, multiple\n  independent method definitions must be supplied.  If overloaded with\n  same arity in an interface you must specify complete hints to\n  disambiguate - a missing hint implies Object.\n\n  recur works to method heads The method bodies of reify are lexical\n  closures, and can refer to the surrounding local scope:\n  \n  (str (let [f \"foo\"] \n       (reify Object \n         (toString [this] f))))\n  == \"foo\"\n\n  (seq (let [f \"foo\"] \n       (reify clojure.lang.Seqable \n         (seq [this] (seq f)))))\n  == (\\f \\o \\o))\n  \n  reify always implements clojure.lang.IObj and transfers meta\n  data of the form to the created object.\n  \n  (meta ^{:k :v} (reify Object (toString [this] \"foo\")))\n  == {:k :v}".to_string() },
        CoreSymbol { name: "reify*".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "release-pending-sends".to_string(), params: "([])".to_string(), doc: "Normally, actions sent directly or indirectly during another action\n  are held until the action completes (changes the agent's\n  state). This function can be used to dispatch any pending sent\n  actions immediately. This has no impact on actions sent during a\n  transaction, which are still held until commit. If no action is\n  occurring, does nothing. Returns the number of actions dispatched.".to_string() },
        CoreSymbol { name: "rem".to_string(), params: "([num div])".to_string(), doc: "remainder of dividing numerator by denominator.".to_string() },
        CoreSymbol { name: "remove".to_string(), params: "([pred] [pred coll])".to_string(), doc: "Returns a lazy sequence of the items in coll for which\n  (pred item) returns logical false. pred must be free of side-effects.\n  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "remove-all-methods".to_string(), params: "([multifn])".to_string(), doc: "Removes all of the methods of multimethod.".to_string() },
        CoreSymbol { name: "remove-method".to_string(), params: "([multifn dispatch-val])".to_string(), doc: "Removes the method of multimethod associated with dispatch-value.".to_string() },
        CoreSymbol { name: "remove-ns".to_string(), params: "([sym])".to_string(), doc: "Removes the namespace named by the symbol. Use with caution.\n  Cannot be used to remove the clojure namespace.".to_string() },
        CoreSymbol { name: "remove-tap".to_string(), params: "([f])".to_string(), doc: "Remove f from the tap set.".to_string() },
        CoreSymbol { name: "remove-watch".to_string(), params: "([reference key])".to_string(), doc: "Removes a watch (set by add-watch) from a reference".to_string() },
        CoreSymbol { name: "repeat".to_string(), params: "([x] [n x])".to_string(), doc: "Returns a lazy (infinite!, or length n if supplied) sequence of xs.".to_string() },
        CoreSymbol { name: "repeatedly".to_string(), params: "([f] [n f])".to_string(), doc: "Takes a function of no args, presumably with side effects, and\n  returns an infinite (or length n if supplied) lazy sequence of calls\n  to it".to_string() },
        CoreSymbol { name: "replace".to_string(), params: "([smap] [smap coll])".to_string(), doc: "Given a map of replacement pairs and a vector/collection, returns a\n  vector/seq with any elements = a key in smap replaced with the\n  corresponding val in smap.  Returns a transducer when no collection\n  is provided.".to_string() },
        CoreSymbol { name: "replicate".to_string(), params: "([n x])".to_string(), doc: "DEPRECATED: Use 'repeat' instead.\n   Returns a lazy seq of n xs.".to_string() },
        CoreSymbol { name: "require".to_string(), params: "([& args])".to_string(), doc: "Loads libs, skipping any that are already loaded. Each argument is\n  either a libspec that identifies a lib, a prefix list that identifies\n  multiple libs whose names share a common prefix, or a flag that modifies\n  how all the identified libs are loaded. Use :require in the ns macro\n  in preference to calling this directly.\n\n  Libs\n\n  A 'lib' is a named set of resources in classpath whose contents define a\n  library of Clojure code. Lib names are symbols and each lib is associated\n  with a Clojure namespace and a Java package that share its name. A lib's\n  name also locates its root directory within classpath using Java's\n  package name to classpath-relative path mapping. All resources in a lib\n  should be contained in the directory structure under its root directory.\n  All definitions a lib makes should be in its associated namespace.\n\n  'require loads a lib by loading its root resource. The root resource path\n  is derived from the lib name in the following manner:\n  Consider a lib named by the symbol 'x.y.z; it has the root directory\n  <classpath>/x/y/, and its root resource is <classpath>/x/y/z.clj, or\n  <classpath>/x/y/z.cljc if <classpath>/x/y/z.clj does not exist. The\n  root resource should contain code to create the lib's\n  namespace (usually by using the ns macro) and load any additional\n  lib resources.\n\n  Libspecs\n\n  A libspec is a lib name or a vector containing a lib name followed by\n  options expressed as sequential keywords and arguments.\n\n  Recognized options:\n  :as takes a symbol as its argument and makes that symbol an alias to the\n    lib's namespace in the current namespace.\n  :as-alias takes a symbol as its argument and aliases like :as, however\n    the lib will not be loaded. If the lib has not been loaded, a new\n    empty namespace will be created (as with create-ns).\n  :refer takes a list of symbols to refer from the namespace or the :all\n    keyword to bring in all public vars.\n\n  Prefix Lists\n\n  It's common for Clojure code to depend on several libs whose names have\n  the same prefix. When specifying libs, prefix lists can be used to reduce\n  repetition. A prefix list contains the shared prefix followed by libspecs\n  with the shared prefix removed from the lib names. After removing the\n  prefix, the names that remain must not contain any periods.\n\n  Flags\n\n  A flag is a keyword.\n  Recognized flags: :reload, :reload-all, :verbose\n  :reload forces loading of all the identified libs even if they are\n    already loaded (has no effect on libspecs using :as-alias)\n  :reload-all implies :reload and also forces loading of all libs that the\n    identified libs directly or indirectly load via require or use\n    (has no effect on libspecs using :as-alias)\n  :verbose triggers printing information about each load, alias, and refer\n\n  Example:\n\n  The following would load the libraries clojure.zip and clojure.set\n  abbreviated as 's'.\n\n  (require '(clojure zip [set :as s]))".to_string() },
        CoreSymbol { name: "requiring-resolve".to_string(), params: "([sym])".to_string(), doc: "Resolves namespace-qualified sym per 'resolve'. If initial resolve\nfails, attempts to require sym's namespace and retries.".to_string() },
        CoreSymbol { name: "reset!".to_string(), params: "([atom newval])".to_string(), doc: "Sets the value of atom to newval without regard for the\n  current value. Returns newval.".to_string() },
        CoreSymbol { name: "reset-meta!".to_string(), params: "([iref metadata-map])".to_string(), doc: "Atomically resets the metadata for a namespace/var/ref/agent/atom".to_string() },
        CoreSymbol { name: "reset-thread-binding-frame-impl".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "reset-vals!".to_string(), params: "([atom newval])".to_string(), doc: "Sets the value of atom to newval. Returns [old new], the value of the\n   atom before and after the reset.".to_string() },
        CoreSymbol { name: "resolve".to_string(), params: "([sym] [env sym])".to_string(), doc: "same as (ns-resolve *ns* symbol) or (ns-resolve *ns* &env symbol)".to_string() },
        CoreSymbol { name: "rest".to_string(), params: "([coll])".to_string(), doc: "Returns a possibly empty seq of the items after the first. Calls seq on its\n  argument.".to_string() },
        CoreSymbol { name: "restart-agent".to_string(), params: "([a new-state & options])".to_string(), doc: "When an agent is failed, changes the agent state to new-state and\n  then un-fails the agent so that sends are allowed again.  If\n  a :clear-actions true option is given, any actions queued on the\n  agent that were being held while it was failed will be discarded,\n  otherwise those held actions will proceed.  The new-state must pass\n  the validator if any, or restart will throw an exception and the\n  agent will remain failed with its old state and error.  Watchers, if\n  any, will NOT be notified of the new state.  Throws an exception if\n  the agent is not failed.".to_string() },
        CoreSymbol { name: "reverse".to_string(), params: "([coll])".to_string(), doc: "Returns a seq of the items in coll in reverse order. Not lazy.".to_string() },
        CoreSymbol { name: "reversible?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll implements Reversible".to_string() },
        CoreSymbol { name: "rseq".to_string(), params: "([rev])".to_string(), doc: "Returns, in constant time, a seq of the items in rev (which\n  can be a vector or sorted-map), in reverse order. If rev is empty returns nil".to_string() },
        CoreSymbol { name: "rsubseq".to_string(), params: "([sc test key] [sc start-test start-key end-test end-key])".to_string(), doc: "sc must be a sorted collection, test(s) one of <, <=, > or\n  >=. Returns a reverse seq of those entries with keys ek for\n  which (test (.. sc comparator (compare ek key)) 0) is true".to_string() },
        CoreSymbol { name: "run!".to_string(), params: "([proc coll])".to_string(), doc: "Runs the supplied procedure (via reduce), for purposes of side\n  effects, on successive items in the collection. Returns nil".to_string() },
        CoreSymbol { name: "satisfies?".to_string(), params: "([protocol x])".to_string(), doc: "Returns true if x satisfies the protocol".to_string() },
        CoreSymbol { name: "second".to_string(), params: "([x])".to_string(), doc: "Same as (first (next x))".to_string() },
        CoreSymbol { name: "select-keys".to_string(), params: "([map keyseq])".to_string(), doc: "Returns a map containing only those entries in map whose key is in keys".to_string() },
        CoreSymbol { name: "send".to_string(), params: "([a f & args])".to_string(), doc: "Dispatch an action to an agent. Returns the agent immediately.\n  Subsequently, in a thread from a thread pool, the state of the agent\n  will be set to the value of:\n\n  (apply action-fn state-of-agent args)".to_string() },
        CoreSymbol { name: "send-off".to_string(), params: "([a f & args])".to_string(), doc: "Dispatch a potentially blocking action to an agent. Returns the\n  agent immediately. Subsequently, in a separate thread, the state of\n  the agent will be set to the value of:\n\n  (apply action-fn state-of-agent args)".to_string() },
        CoreSymbol { name: "send-via".to_string(), params: "([executor a f & args])".to_string(), doc: "Dispatch an action to an agent. Returns the agent immediately.\n  Subsequently, in a thread supplied by executor, the state of the agent\n  will be set to the value of:\n\n  (apply action-fn state-of-agent args)".to_string() },
        CoreSymbol { name: "seq".to_string(), params: "([coll])".to_string(), doc: "Returns a seq on the collection. If the collection is\n    empty, returns nil.  (seq nil) returns nil. seq also works on\n    Strings, native Java arrays (of reference types) and any objects\n    that implement Iterable. Note that seqs cache values, thus seq\n    should not be used on any Iterable whose iterator repeatedly\n    returns the same mutable object.".to_string() },
        CoreSymbol { name: "seq-to-map-for-destructuring".to_string(), params: "([s])".to_string(), doc: "Builds a map from a seq as described in\n  https://clojure.org/reference/special_forms#keyword-arguments".to_string() },
        CoreSymbol { name: "seq?".to_string(), params: "([x])".to_string(), doc: "Return true if x implements ISeq".to_string() },
        CoreSymbol { name: "seqable?".to_string(), params: "([x])".to_string(), doc: "Return true if the seq function is supported for x".to_string() },
        CoreSymbol { name: "seque".to_string(), params: "([s] [n-or-q s])".to_string(), doc: "Creates a queued seq on another (presumably lazy) seq s. The queued\n  seq will produce a concrete seq in the background, and can get up to\n  n items ahead of the consumer. n-or-q can be an integer n buffer\n  size, or an instance of java.util.concurrent BlockingQueue. Note\n  that reading from a seque can block if the reader gets ahead of the\n  producer.".to_string() },
        CoreSymbol { name: "sequence".to_string(), params: "([coll] [xform coll] [xform coll & colls])".to_string(), doc: "Coerces coll to a (possibly empty) sequence, if it is not already\n  one. Will not force a lazy seq. (sequence nil) yields (), When a\n  transducer is supplied, returns a lazy sequence of applications of\n  the transform to the items in coll(s), i.e. to the set of first\n  items of each coll, followed by the set of second\n  items in each coll, until any one of the colls is exhausted.  Any\n  remaining items in other colls are ignored. The transform should accept\n  number-of-colls arguments".to_string() },
        CoreSymbol { name: "sequential?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll implements Sequential".to_string() },
        CoreSymbol { name: "set".to_string(), params: "([coll])".to_string(), doc: "Returns a set of the distinct elements of coll.".to_string() },
        CoreSymbol { name: "set-agent-send-executor!".to_string(), params: "([executor])".to_string(), doc: "Sets the ExecutorService to be used by send".to_string() },
        CoreSymbol { name: "set-agent-send-off-executor!".to_string(), params: "([executor])".to_string(), doc: "Sets the ExecutorService to be used by send-off".to_string() },
        CoreSymbol { name: "set-error-handler!".to_string(), params: "([a handler-fn])".to_string(), doc: "Sets the error-handler of agent a to handler-fn.  If an action\n  being run by the agent throws an exception or doesn't pass the\n  validator fn, handler-fn will be called with two arguments: the\n  agent and the exception.".to_string() },
        CoreSymbol { name: "set-error-mode!".to_string(), params: "([a mode-keyword])".to_string(), doc: "Sets the error-mode of agent a to mode-keyword, which must be\n  either :fail or :continue.  If an action being run by the agent\n  throws an exception or doesn't pass the validator fn, an\n  error-handler may be called (see set-error-handler!), after which,\n  if the mode is :continue, the agent will continue as if neither the\n  action that caused the error nor the error itself ever happened.\n  \n  If the mode is :fail, the agent will become failed and will stop\n  accepting new 'send' and 'send-off' actions, and any previously\n  queued actions will be held until a 'restart-agent'.  Deref will\n  still work, returning the state of the agent before the error.".to_string() },
        CoreSymbol { name: "set-validator!".to_string(), params: "([iref validator-fn])".to_string(), doc: "Sets the validator-fn for a var/ref/agent/atom. validator-fn must be nil or a\n  side-effect-free fn of one argument, which will be passed the intended\n  new state on any state change. If the new state is unacceptable, the\n  validator-fn should return false or throw an exception. If the current state (root\n  value if var) is not acceptable to the new validator, an exception\n  will be thrown and the validator will not be changed.".to_string() },
        CoreSymbol { name: "set?".to_string(), params: "([x])".to_string(), doc: "Returns true if x implements IPersistentSet".to_string() },
        CoreSymbol { name: "short".to_string(), params: "([x])".to_string(), doc: "Coerce to short".to_string() },
        CoreSymbol { name: "short-array".to_string(), params: "([size-or-seq] [size init-val-or-seq])".to_string(), doc: "Creates an array of shorts".to_string() },
        CoreSymbol { name: "shorts".to_string(), params: "([xs])".to_string(), doc: "Casts to shorts[]".to_string() },
        CoreSymbol { name: "shuffle".to_string(), params: "([coll])".to_string(), doc: "Return a random permutation of coll".to_string() },
        CoreSymbol { name: "shutdown-agents".to_string(), params: "([])".to_string(), doc: "Initiates a shutdown of the thread pools that back the agent\n  system. Running actions will complete, but no new actions will be\n  accepted".to_string() },
        CoreSymbol { name: "simple-ident?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a symbol or keyword without a namespace".to_string() },
        CoreSymbol { name: "simple-keyword?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a keyword without a namespace".to_string() },
        CoreSymbol { name: "simple-symbol?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a symbol without a namespace".to_string() },
        CoreSymbol { name: "slurp".to_string(), params: "([f & opts])".to_string(), doc: "Opens a reader on f and reads all its contents, returning a string.\n  See clojure.java.io/reader for a complete list of supported arguments.".to_string() },
        CoreSymbol { name: "some".to_string(), params: "([pred coll])".to_string(), doc: "Returns the first logical true value of (pred x) for any x in coll,\n  else nil.  One common idiom is to use a set as pred, for example\n  this will return :fred if :fred is in the sequence, otherwise nil:\n  (some #{:fred} coll)".to_string() },
        CoreSymbol { name: "some->".to_string(), params: "([expr & forms])".to_string(), doc: "When expr is not nil, threads it into the first form (via ->),\n  and when that result is not nil, through the next etc".to_string() },
        CoreSymbol { name: "some->>".to_string(), params: "([expr & forms])".to_string(), doc: "When expr is not nil, threads it into the first form (via ->>),\n  and when that result is not nil, through the next etc".to_string() },
        CoreSymbol { name: "some-fn".to_string(), params: "([p] [p1 p2] [p1 p2 p3] [p1 p2 p3 & ps])".to_string(), doc: "Takes a set of predicates and returns a function f that returns the first logical true value\n  returned by one of its composing predicates against any of its arguments, else it returns\n  logical false. Note that f is short-circuiting in that it will stop execution on the first\n  argument that triggers a logical true result against the original predicates.".to_string() },
        CoreSymbol { name: "some?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is not nil, false otherwise.".to_string() },
        CoreSymbol { name: "sort".to_string(), params: "([coll] [comp coll])".to_string(), doc: "Returns a sorted sequence of the items in coll. If no comparator is\n  supplied, uses compare.  comparator must implement\n  java.util.Comparator.  Guaranteed to be stable: equal elements will\n  not be reordered.  If coll is a Java array, it will be modified.  To\n  avoid this, sort a copy of the array.".to_string() },
        CoreSymbol { name: "sort-by".to_string(), params: "([keyfn coll] [keyfn comp coll])".to_string(), doc: "Returns a sorted sequence of the items in coll, where the sort\n  order is determined by comparing (keyfn item).  If no comparator is\n  supplied, uses compare.  comparator must implement\n  java.util.Comparator.  Guaranteed to be stable: equal elements will\n  not be reordered.  If coll is a Java array, it will be modified.  To\n  avoid this, sort a copy of the array.".to_string() },
        CoreSymbol { name: "sorted-map".to_string(), params: "([& keyvals])".to_string(), doc: "keyval => key val\n  Returns a new sorted map with supplied mappings.  If any keys are\n  equal, they are handled as if by repeated uses of assoc.".to_string() },
        CoreSymbol { name: "sorted-map-by".to_string(), params: "([comparator & keyvals])".to_string(), doc: "keyval => key val\n  Returns a new sorted map with supplied mappings, using the supplied\n  comparator.  If any keys are equal, they are handled as if by\n  repeated uses of assoc.".to_string() },
        CoreSymbol { name: "sorted-set".to_string(), params: "([& keys])".to_string(), doc: "Returns a new sorted set with supplied keys.  Any equal keys are\n  handled as if by repeated uses of conj.".to_string() },
        CoreSymbol { name: "sorted-set-by".to_string(), params: "([comparator & keys])".to_string(), doc: "Returns a new sorted set with supplied keys, using the supplied\n  comparator.  Any equal keys are handled as if by repeated uses of\n  conj.".to_string() },
        CoreSymbol { name: "sorted?".to_string(), params: "([coll])".to_string(), doc: "Returns true if coll implements Sorted".to_string() },
        CoreSymbol { name: "special-symbol?".to_string(), params: "([s])".to_string(), doc: "Returns true if s names a special form".to_string() },
        CoreSymbol { name: "spit".to_string(), params: "([f content & options])".to_string(), doc: "Opposite of slurp.  Opens f with writer, writes content, then\n  closes f. Options passed to clojure.java.io/writer.".to_string() },
        CoreSymbol { name: "split-at".to_string(), params: "([n coll])".to_string(), doc: "Returns a vector of [(take n coll) (drop n coll)]".to_string() },
        CoreSymbol { name: "split-with".to_string(), params: "([pred coll])".to_string(), doc: "Returns a vector of [(take-while pred coll) (drop-while pred coll)]".to_string() },
        CoreSymbol { name: "str".to_string(), params: "([] [x] [x & ys])".to_string(), doc: "With no args, returns the empty string. With one arg x, returns\n  x.toString().  (str nil) returns the empty string. With more than\n  one arg, returns the concatenation of the str values of the args.".to_string() },
        CoreSymbol { name: "string?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a String".to_string() },
        CoreSymbol { name: "subs".to_string(), params: "([s start] [s start end])".to_string(), doc: "Returns the substring of s beginning at start inclusive, and ending\n  at end (defaults to length of string), exclusive.".to_string() },
        CoreSymbol { name: "subseq".to_string(), params: "([sc test key] [sc start-test start-key end-test end-key])".to_string(), doc: "sc must be a sorted collection, test(s) one of <, <=, > or\n  >=. Returns a seq of those entries with keys ek for\n  which (test (.. sc comparator (compare ek key)) 0) is true".to_string() },
        CoreSymbol { name: "subvec".to_string(), params: "([v start] [v start end])".to_string(), doc: "Returns a persistent vector of the items in vector from\n  start (inclusive) to end (exclusive).  If end is not supplied,\n  defaults to (count vector). This operation is O(1) and very fast, as\n  the resulting vector shares structure with the original and no\n  trimming is done.".to_string() },
        CoreSymbol { name: "supers".to_string(), params: "([class])".to_string(), doc: "Returns the immediate and indirect superclasses and interfaces of c, if any".to_string() },
        CoreSymbol { name: "swap!".to_string(), params: "([atom f] [atom f x] [atom f x y] [atom f x y & args])".to_string(), doc: "Atomically swaps the value of atom to be:\n  (apply f current-value-of-atom args). Note that f may be called\n  multiple times, and thus should be free of side effects.  Returns\n  the value that was swapped in.".to_string() },
        CoreSymbol { name: "swap-vals!".to_string(), params: "([atom f] [atom f x] [atom f x y] [atom f x y & args])".to_string(), doc: "Atomically swaps the value of atom to be:\n  (apply f current-value-of-atom args). Note that f may be called\n  multiple times, and thus should be free of side effects.\n  Returns [old new], the value of the atom before and after the swap.".to_string() },
        CoreSymbol { name: "symbol".to_string(), params: "([name] [ns name])".to_string(), doc: "Returns a Symbol with the given namespace and name. Arity-1 works\n  on strings, keywords, and vars.".to_string() },
        CoreSymbol { name: "symbol?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a Symbol".to_string() },
        CoreSymbol { name: "sync".to_string(), params: "([_flags-ignored-for-now & body])".to_string(), doc: "transaction-flags => TBD, pass nil for now\n  Runs the exprs (in an implicit do) in a transaction that encompasses\n  exprs and any nested calls.  Starts a transaction if none is already\n  running on this thread. Any uncaught exception will abort the\n  transaction and flow out of sync. The exprs may be run more than\n  once, but any effects on Refs will be atomic.".to_string() },
        CoreSymbol { name: "tagged-literal".to_string(), params: "([tag form])".to_string(), doc: "Construct a data representation of a tagged literal from a\n  tag symbol and a form.".to_string() },
        CoreSymbol { name: "tagged-literal?".to_string(), params: "([value])".to_string(), doc: "Return true if the value is the data representation of a tagged literal".to_string() },
        CoreSymbol { name: "take".to_string(), params: "([n] [n coll])".to_string(), doc: "Returns a lazy sequence of the first n items in coll, or all items if\n  there are fewer than n.  Returns a stateful transducer when\n  no collection is provided.".to_string() },
        CoreSymbol { name: "take-last".to_string(), params: "([n coll])".to_string(), doc: "Returns a seq of the last n items in coll.  Depending on the type\n  of coll may be no better than linear time.  For vectors, see also subvec.".to_string() },
        CoreSymbol { name: "take-nth".to_string(), params: "([n] [n coll])".to_string(), doc: "Returns a lazy seq of every nth item in coll.  Returns a stateful\n  transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "take-while".to_string(), params: "([pred] [pred coll])".to_string(), doc: "Returns a lazy sequence of successive items from coll while\n  (pred item) returns logical true. pred must be free of side-effects.\n  Returns a transducer when no collection is provided.".to_string() },
        CoreSymbol { name: "tap>".to_string(), params: "([x])".to_string(), doc: "sends x to any taps. Will not block. Returns true if there was room in the queue,\n  false if not (dropped).".to_string() },
        CoreSymbol { name: "test".to_string(), params: "([v])".to_string(), doc: "test [v] finds fn at key :test in var metadata and calls it,\n  presuming failure will throw exception".to_string() },
        CoreSymbol { name: "the-ns".to_string(), params: "([x])".to_string(), doc: "If passed a namespace, returns it. Else, when passed a symbol,\n  returns the namespace named by it, throwing an exception if not\n  found.".to_string() },
        CoreSymbol { name: "thread-bound?".to_string(), params: "([& vars])".to_string(), doc: "Returns true if all of the vars provided as arguments have thread-local bindings.\n   Implies that set!'ing the provided vars will succeed.  Returns true if no vars are provided.".to_string() },
        CoreSymbol { name: "time".to_string(), params: "([expr])".to_string(), doc: "Evaluates expr and prints the time it took.  Returns the value of\n expr.".to_string() },
        CoreSymbol { name: "to-array".to_string(), params: "([coll])".to_string(), doc: "Returns an array of Objects containing the contents of coll, which\n  can be any Collection.  Maps to java.util.Collection.toArray().".to_string() },
        CoreSymbol { name: "to-array-2d".to_string(), params: "([coll])".to_string(), doc: "Returns a (potentially-ragged) 2-dimensional array of Objects\n  containing the contents of coll, which can be any Collection of any\n  Collection.".to_string() },
        CoreSymbol { name: "trampoline".to_string(), params: "([f] [f & args])".to_string(), doc: "trampoline can be used to convert algorithms requiring mutual\n  recursion without stack consumption. Calls f with supplied args, if\n  any. If f returns a fn, calls that fn with no arguments, and\n  continues to repeat, until the return value is not a fn, then\n  returns that non-fn value. Note that if you want to return a fn as a\n  final value, you must wrap it in some data structure and unpack it\n  after trampoline returns.".to_string() },
        CoreSymbol { name: "transduce".to_string(), params: "([xform f coll] [xform f init coll])".to_string(), doc: "reduce with a transformation of f (xf). If init is not\n  supplied, (f) will be called to produce it. f should be a reducing\n  step function that accepts both 1 and 2 arguments, if it accepts\n  only 2 you can add the arity-1 with 'completing'. Returns the result\n  of applying (the transformed) xf to init and the first item in coll,\n  then applying xf to that result and the 2nd item, etc. If coll\n  contains no items, returns init and f is not called. Note that\n  certain transforms may inject or skip items.".to_string() },
        CoreSymbol { name: "transient".to_string(), params: "([coll])".to_string(), doc: "Returns a new, transient version of the collection, in constant time.".to_string() },
        CoreSymbol { name: "tree-seq".to_string(), params: "([branch? children root])".to_string(), doc: "Returns a lazy sequence of the nodes in a tree, via a depth-first walk.\n   branch? must be a fn of one arg that returns true if passed a node\n   that can have children (but may not).  children must be a fn of one\n   arg that returns a sequence of the children. Will only be called on\n   nodes for which branch? returns true. Root is the root node of the\n  tree.".to_string() },
        CoreSymbol { name: "true?".to_string(), params: "([x])".to_string(), doc: "Returns true if x is the value true, false otherwise.".to_string() },
        CoreSymbol { name: "type".to_string(), params: "([x])".to_string(), doc: "Returns the :type metadata of x, or its Class if none".to_string() },
        CoreSymbol { name: "unchecked-add".to_string(), params: "([x y])".to_string(), doc: "Returns the sum of x and y, both long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-add-int".to_string(), params: "([x y])".to_string(), doc: "Returns the sum of x and y, both int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-byte".to_string(), params: "([x])".to_string(), doc: "Coerce to byte. Subject to rounding or truncation.".to_string() },
        CoreSymbol { name: "unchecked-char".to_string(), params: "([x])".to_string(), doc: "Coerce to char. Subject to rounding or truncation.".to_string() },
        CoreSymbol { name: "unchecked-dec".to_string(), params: "([x])".to_string(), doc: "Returns a number one less than x, a long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-dec-int".to_string(), params: "([x])".to_string(), doc: "Returns a number one less than x, an int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-divide-int".to_string(), params: "([x y])".to_string(), doc: "Returns the division of x by y, both int.\n  Note - uses a primitive operator subject to truncation.".to_string() },
        CoreSymbol { name: "unchecked-double".to_string(), params: "([x])".to_string(), doc: "Coerce to double. Subject to rounding.".to_string() },
        CoreSymbol { name: "unchecked-float".to_string(), params: "([x])".to_string(), doc: "Coerce to float. Subject to rounding.".to_string() },
        CoreSymbol { name: "unchecked-inc".to_string(), params: "([x])".to_string(), doc: "Returns a number one greater than x, a long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-inc-int".to_string(), params: "([x])".to_string(), doc: "Returns a number one greater than x, an int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-int".to_string(), params: "([x])".to_string(), doc: "Coerce to int. Subject to rounding or truncation.".to_string() },
        CoreSymbol { name: "unchecked-long".to_string(), params: "([x])".to_string(), doc: "Coerce to long. Subject to rounding or truncation.".to_string() },
        CoreSymbol { name: "unchecked-multiply".to_string(), params: "([x y])".to_string(), doc: "Returns the product of x and y, both long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-multiply-int".to_string(), params: "([x y])".to_string(), doc: "Returns the product of x and y, both int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-negate".to_string(), params: "([x])".to_string(), doc: "Returns the negation of x, a long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-negate-int".to_string(), params: "([x])".to_string(), doc: "Returns the negation of x, an int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-remainder-int".to_string(), params: "([x y])".to_string(), doc: "Returns the remainder of division of x by y, both int.\n  Note - uses a primitive operator subject to truncation.".to_string() },
        CoreSymbol { name: "unchecked-short".to_string(), params: "([x])".to_string(), doc: "Coerce to short. Subject to rounding or truncation.".to_string() },
        CoreSymbol { name: "unchecked-subtract".to_string(), params: "([x y])".to_string(), doc: "Returns the difference of x and y, both long.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "unchecked-subtract-int".to_string(), params: "([x y])".to_string(), doc: "Returns the difference of x and y, both int.\n  Note - uses a primitive operator subject to overflow.".to_string() },
        CoreSymbol { name: "underive".to_string(), params: "([tag parent] [h tag parent])".to_string(), doc: "Removes a parent/child relationship between parent and\n  tag. h must be a hierarchy obtained from make-hierarchy, if not\n  supplied defaults to, and modifies, the global hierarchy.".to_string() },
        CoreSymbol { name: "unquote".to_string(), params: "".to_string(), doc: "".to_string() },
        CoreSymbol { name: "unreduced".to_string(), params: "([x])".to_string(), doc: "If x is reduced?, returns (deref x), else returns x".to_string() },
        CoreSymbol { name: "unsigned-bit-shift-right".to_string(), params: "([x n])".to_string(), doc: "Bitwise shift right, without sign-extension.".to_string() },
        CoreSymbol { name: "update".to_string(), params: "([m k f] [m k f x] [m k f x y] [m k f x y z] [m k f x y z & more])".to_string(), doc: "'Updates' a value in an associative structure, where k is a\n  key and f is a function that will take the old value\n  and any supplied args and return the new value, and returns a new\n  structure.  If the key does not exist, nil is passed as the old value.".to_string() },
        CoreSymbol { name: "update-in".to_string(), params: "([m ks f & args])".to_string(), doc: "'Updates' a value in a nested associative structure, where ks is a\n  sequence of keys and f is a function that will take the old value\n  and any supplied args and return the new value, and returns a new\n  nested structure.  If any levels do not exist, hash-maps will be\n  created.".to_string() },
        CoreSymbol { name: "update-keys".to_string(), params: "([m f])".to_string(), doc: "m f => {(f k) v ...}\n\n  Given a map m and a function f of 1-argument, returns a new map whose\n  keys are the result of applying f to the keys of m, mapped to the\n  corresponding values of m.\n  f must return a unique key for each key of m, else the behavior is undefined.".to_string() },
        CoreSymbol { name: "update-vals".to_string(), params: "([m f])".to_string(), doc: "m f => {k (f v) ...}\n\n  Given a map m and a function f of 1-argument, returns a new map where the keys of m\n  are mapped to result of applying f to the corresponding values of m.".to_string() },
        CoreSymbol { name: "uri?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a java.net.URI".to_string() },
        CoreSymbol { name: "use".to_string(), params: "([& args])".to_string(), doc: "Like 'require, but also refers to each lib's namespace using\n  clojure.core/refer. Use :use in the ns macro in preference to calling\n  this directly.\n\n  'use accepts additional options in libspecs: :exclude, :only, :rename.\n  The arguments and semantics for :exclude, :only, and :rename are the same\n  as those documented for clojure.core/refer.".to_string() },
        CoreSymbol { name: "uuid?".to_string(), params: "([x])".to_string(), doc: "Return true if x is a java.util.UUID".to_string() },
        CoreSymbol { name: "val".to_string(), params: "([e])".to_string(), doc: "Returns the value in the map entry.".to_string() },
        CoreSymbol { name: "vals".to_string(), params: "([map])".to_string(), doc: "Returns a sequence of the map's values, in the same order as (seq map).".to_string() },
        CoreSymbol { name: "var-get".to_string(), params: "([x])".to_string(), doc: "Gets the value in the var object".to_string() },
        CoreSymbol { name: "var-set".to_string(), params: "([x val])".to_string(), doc: "Sets the value in the var object to val. The var must be\n thread-locally bound.".to_string() },
        CoreSymbol { name: "var?".to_string(), params: "([v])".to_string(), doc: "Returns true if v is of type clojure.lang.Var".to_string() },
        CoreSymbol { name: "vary-meta".to_string(), params: "([obj f & args])".to_string(), doc: "Returns an object of the same type and value as obj, with\n  (apply f (meta obj) args) as its metadata.".to_string() },
        CoreSymbol { name: "vec".to_string(), params: "([coll])".to_string(), doc: "Creates a new vector containing the contents of coll. Java arrays\n  will be aliased and should not be modified.".to_string() },
        CoreSymbol { name: "vector".to_string(), params: "([] [a] [a b] [a b c] [a b c d] [a b c d e] [a b c d e f] [a b c d e f & args])".to_string(), doc: "Creates a new vector containing the args.".to_string() },
        CoreSymbol { name: "vector?".to_string(), params: "([x])".to_string(), doc: "Return true if x implements IPersistentVector".to_string() },
        CoreSymbol { name: "volatile!".to_string(), params: "([val])".to_string(), doc: "Creates and returns a Volatile with an initial value of val.".to_string() },
        CoreSymbol { name: "vreset!".to_string(), params: "([vol newval])".to_string(), doc: "Sets the value of volatile to newval without regard for the\n   current value. Returns newval.".to_string() },
        CoreSymbol { name: "vswap!".to_string(), params: "([vol f & args])".to_string(), doc: "Non-atomically swaps the value of the volatile as if:\n   (apply f current-value-of-vol args). Returns the value that\n   was swapped in.".to_string() },
        CoreSymbol { name: "when".to_string(), params: "([test & body])".to_string(), doc: "Evaluates test. If logical true, evaluates body in an implicit do.".to_string() },
        CoreSymbol { name: "when-first".to_string(), params: "([bindings & body])".to_string(), doc: "bindings => x xs\n\n  Roughly the same as (when (seq xs) (let [x (first xs)] body)) but xs is evaluated only once".to_string() },
        CoreSymbol { name: "when-let".to_string(), params: "([bindings & body])".to_string(), doc: "bindings => binding-form test\n\n  When test is true, evaluates body with binding-form bound to the value of test".to_string() },
        CoreSymbol { name: "when-not".to_string(), params: "([test & body])".to_string(), doc: "Evaluates test. If logical false, evaluates body in an implicit do.".to_string() },
        CoreSymbol { name: "when-some".to_string(), params: "([bindings & body])".to_string(), doc: "bindings => binding-form test\n\n   When test is not nil, evaluates body with binding-form bound to the\n   value of test".to_string() },
        CoreSymbol { name: "while".to_string(), params: "([test & body])".to_string(), doc: "Repeatedly executes body while test expression is true. Presumes\n  some side-effect will cause test to become false/nil. Returns nil".to_string() },
        CoreSymbol { name: "with-bindings".to_string(), params: "([binding-map & body])".to_string(), doc: "Takes a map of Var/value pairs. Installs for the given Vars the associated\n  values as thread-local bindings. Then executes body. Pops the installed\n  bindings after body was evaluated. Returns the value of body.".to_string() },
        CoreSymbol { name: "with-bindings*".to_string(), params: "([binding-map f & args])".to_string(), doc: "Takes a map of Var/value pairs. Installs for the given Vars the associated\n  values as thread-local bindings. Then calls f with the supplied arguments.\n  Pops the installed bindings after f returned. Returns whatever f returns.".to_string() },
        CoreSymbol { name: "with-in-str".to_string(), params: "([s & body])".to_string(), doc: "Evaluates body in a context in which *in* is bound to a fresh\n  StringReader initialized with the string s.".to_string() },
        CoreSymbol { name: "with-local-vars".to_string(), params: "([name-vals-vec & body])".to_string(), doc: "varbinding=> symbol init-expr\n\n  Executes the exprs in a context in which the symbols are bound to\n  vars with per-thread bindings to the init-exprs.  The symbols refer\n  to the var objects themselves, and must be accessed with var-get and\n  var-set".to_string() },
        CoreSymbol { name: "with-meta".to_string(), params: "([obj m])".to_string(), doc: "Returns an object of the same type and value as obj, with\n    map m as its metadata.".to_string() },
        CoreSymbol { name: "with-open".to_string(), params: "([bindings & body])".to_string(), doc: "bindings => [name init ...]\n\n  Evaluates body in a try expression with names bound to the values\n  of the inits, and a finally clause that calls (.close name) on each\n  name in reverse order.".to_string() },
        CoreSymbol { name: "with-out-str".to_string(), params: "([& body])".to_string(), doc: "Evaluates exprs in a context in which *out* is bound to a fresh\n  StringWriter.  Returns the string created by any nested printing\n  calls.".to_string() },
        CoreSymbol { name: "with-precision".to_string(), params: "([precision & exprs])".to_string(), doc: "Sets the precision and rounding mode to be used for BigDecimal operations.\n\n  Usage: (with-precision 10 (/ 1M 3))\n  or:    (with-precision 10 :rounding HALF_DOWN (/ 1M 3))\n\n  The rounding mode is one of CEILING, FLOOR, HALF_UP, HALF_DOWN,\n  HALF_EVEN, UP, DOWN and UNNECESSARY; it defaults to HALF_UP.".to_string() },
        CoreSymbol { name: "with-redefs".to_string(), params: "([bindings & body])".to_string(), doc: "binding => var-symbol temp-value-expr\n\n  Temporarily redefines Vars while executing the body.  The\n  temp-value-exprs will be evaluated and each resulting value will\n  replace in parallel the root value of its Var.  After the body is\n  executed, the root values of all the Vars will be set back to their\n  old values.  These temporary changes will be visible in all threads.\n  Useful for mocking out functions during testing.".to_string() },
        CoreSymbol { name: "with-redefs-fn".to_string(), params: "([binding-map func])".to_string(), doc: "Temporarily redefines Vars during a call to func.  Each val of\n  binding-map will replace the root value of its key which must be\n  a Var.  After func is called with no args, the root values of all\n  the Vars will be set back to their old values.  These temporary\n  changes will be visible in all threads.  Useful for mocking out\n  functions during testing.".to_string() },
        CoreSymbol { name: "xml-seq".to_string(), params: "([root])".to_string(), doc: "A tree seq on the xml elements as per xml/parse".to_string() },
        CoreSymbol { name: "zero?".to_string(), params: "([num])".to_string(), doc: "Returns true if num is zero, else false".to_string() },
        CoreSymbol { name: "zipmap".to_string(), params: "([keys vals])".to_string(), doc: "Returns a map with the keys mapped to the corresponding vals.".to_string() },
    ]
}
